#include "biblia.h"

void Biblia::CarregarMateus(Biblia* b) {
    b->dados[MATEUS].nome = wxT("Mateus");

    b->dados[MATEUS].capitulos[1].versos[1] = wxT("Livro da genealogia de Jesus Cristo, filho de Davi, filho de Abraão.");
    b->dados[MATEUS].capitulos[1].versos[2] = wxT("A Abraão nasceu Isaque; a Isaque nasceu Jacó; a Jacó nasceram Judá e seus irmãos;");
    b->dados[MATEUS].capitulos[1].versos[3] = wxT("a Judá nasceram, de Tamar, Farés e Zará; a Farés nasceu Esrom; a Esrom nasceu Arão;");
    b->dados[MATEUS].capitulos[1].versos[4] = wxT("a Arão nasceu Aminadabe; a Aminadabe nasceu Nasom; a Nasom nasceu Salmom;");
    b->dados[MATEUS].capitulos[1].versos[5] = wxT("a Salmom nasceu, de Raabe, Booz; a Booz nasceu, de Rute, Obede; a Obede nasceu Jessé;");
    b->dados[MATEUS].capitulos[1].versos[6] = wxT("e a Jessé nasceu o rei Davi. A Davi nasceu Salomão da que fora mulher de Urias;");
    b->dados[MATEUS].capitulos[1].versos[7] = wxT("a Salomão nasceu Roboão; a Roboão nasceu Abias; a nasceu Abias nasceu Asafe;");
    b->dados[MATEUS].capitulos[1].versos[8] = wxT("a Asafe nasceu Josafá; a Josafá nasceu Jorão; a Jorão Ozias;");
    b->dados[MATEUS].capitulos[1].versos[9] = wxT("a Ozias nasceu Joatão; a Joatão nasceu Acaz; a Acaz nasceu Ezequias;");
    b->dados[MATEUS].capitulos[1].versos[10] = wxT("a Ezequias nasceu Manassés; a Manassés nasceu Amom; a Amom nasceu Josias;");
    b->dados[MATEUS].capitulos[1].versos[11] = wxT("a Josias nasceram Jeconias e seus irmãos, no tempo da deportação para Babilônia.");
    b->dados[MATEUS].capitulos[1].versos[12] = wxT("Depois da deportação para Babilônia nasceu a Jeconias, Salatiel; a Salatiel nasceu Zorobabel;");
    b->dados[MATEUS].capitulos[1].versos[13] = wxT("a Zorobabel nasceu Abiúde; a Abiúde nasceu Eliaquim; a Eliaquim nasceu Azor;");
    b->dados[MATEUS].capitulos[1].versos[14] = wxT("a Azor nasceu Sadoque; a Sadoque nasceu Aquim; a Aquim nasceu Eliúde;");
    b->dados[MATEUS].capitulos[1].versos[15] = wxT("a Eliúde nasceu Eleazar; a Eleazar nasceu Matã; a Matã nasceu Jacó;");
    b->dados[MATEUS].capitulos[1].versos[16] = wxT("e a Jacó nasceu José, marido de Maria, da qual nasceu JESUS, que se chama Cristo.");
    b->dados[MATEUS].capitulos[1].versos[17] = wxT("De sorte que todas as gerações, desde Abraão até Davi, são catorze gerações; e desde Davi até a deportação para Babilônia, catorze gerações; e desde a deportação para Babilônia até o Cristo, catorze gerações.");
    b->dados[MATEUS].capitulos[1].versos[18] = wxT("Ora, o nascimento de Jesus Cristo foi assim: Estando Maria, sua mãe, desposada com José, antes de se ajuntarem, ela se achou ter concebido do Espírito Santo.");
    b->dados[MATEUS].capitulos[1].versos[19] = wxT("E como José, seu esposo, era justo, e não a queria infamar, intentou deixá-la secretamente.");
    b->dados[MATEUS].capitulos[1].versos[20] = wxT("E, projetando ele isso, eis que em sonho lhe apareceu um anjo do Senhor, dizendo: José, filho de Davi, não temas receber a Maria, tua mulher, pois o que nela se gerou é do Espírito Santo;");
    b->dados[MATEUS].capitulos[1].versos[21] = wxT("ela dará à luz um filho, a quem chamarás JESUS; porque ele salvará o seu povo dos seus pecados.");
    b->dados[MATEUS].capitulos[1].versos[22] = wxT("Ora, tudo isso aconteceu para que se cumprisse o que fora dito da parte do Senhor pelo profeta:");
    b->dados[MATEUS].capitulos[1].versos[23] = wxT("Eis que a virgem conceberá e dará à luz um filho, o qual será chamado EMANUEL, que traduzido é: Deus conosco.");
    b->dados[MATEUS].capitulos[1].versos[24] = wxT("E José, tendo despertado do sono, fez como o anjo do Senhor lhe ordenara, e recebeu sua mulher;");
    b->dados[MATEUS].capitulos[1].versos[25] = wxT("e não a conheceu enquanto ela não deu à luz um filho; e pôs-lhe o nome de JESUS.");

    b->dados[MATEUS].capitulos[2].versos[1] = wxT("Tendo, pois, nascido Jesus em Belém da Judéia, no tempo do rei Herodes, eis que vieram do oriente a Jerusalém uns magos que perguntavam:");
    b->dados[MATEUS].capitulos[2].versos[2] = wxT("Onde está aquele que é nascido rei dos judeus? pois do oriente vimos a sua estrela e viemos adorá-lo.");
    b->dados[MATEUS].capitulos[2].versos[3] = wxT("O rei Herodes, ouvindo isso, perturbou-se, e com ele toda a Jerusalém;");
    b->dados[MATEUS].capitulos[2].versos[4] = wxT("e, reunindo todos os principais sacerdotes e os escribas do povo, perguntava-lhes onde havia de nascer o Cristo.");
    b->dados[MATEUS].capitulos[2].versos[5] = wxT("Responderam-lhe eles: Em Belém da Judéia; pois assim está escrito pelo profeta:");
    b->dados[MATEUS].capitulos[2].versos[6] = wxT("E tu, Belém, terra de Judá, de modo nenhum és a menor entre as principais cidades de Judá; porque de ti sairá o Guia que há de apascentar o meu povo de Israel.");
    b->dados[MATEUS].capitulos[2].versos[7] = wxT("Então Herodes chamou secretamente os magos, e deles inquiriu com precisão acerca do tempo em que a estrela aparecera;");
    b->dados[MATEUS].capitulos[2].versos[8] = wxT("e enviando-os a Belém, disse-lhes: Ide, e perguntai diligentemente pelo menino; e, quando o achardes, participai-mo, para que também eu vá e o adore.");
    b->dados[MATEUS].capitulos[2].versos[9] = wxT("Tendo eles, pois, ouvido o rei, partiram; e eis que a estrela que tinham visto quando no oriente ia adiante deles, até que, chegando, se deteve sobre o lugar onde estava o menino.");
    b->dados[MATEUS].capitulos[2].versos[10] = wxT("Ao verem eles a estrela, regozijaram-se com grande alegria.");
    b->dados[MATEUS].capitulos[2].versos[11] = wxT("E entrando na casa, viram o menino com Maria sua mãe e, prostrando-se, o adoraram; e abrindo os seus tesouros, ofertaram-lhe dádivas: ouro incenso e mirra.");
    b->dados[MATEUS].capitulos[2].versos[12] = wxT("Ora, sendo por divina revelação avisados em sonhos para não voltarem a Herodes, regressaram à sua terra por outro caminho.");
    b->dados[MATEUS].capitulos[2].versos[13] = wxT("E, havendo eles se retirado, eis que um anjo do Senhor apareceu a José em sonho, dizendo: Levanta-te, toma o menino e sua mãe, foge para o Egito, e ali fica até que eu te fale; porque Herodes há de procurar o menino para o matar.");
    b->dados[MATEUS].capitulos[2].versos[14] = wxT("Levantou-se, pois, tomou de noite o menino e sua mãe, e partiu para o Egito.");
    b->dados[MATEUS].capitulos[2].versos[15] = wxT("e lá ficou até a morte de Herodes, para que se cumprisse o que fora dito da parte do Senhor pelo profeta: Do Egito chamei o meu Filho.");
    b->dados[MATEUS].capitulos[2].versos[16] = wxT("Cumpriu-se então o que fora dito pelo profeta Jeremias:");
    b->dados[MATEUS].capitulos[2].versos[17] = wxT("Em Ramá se ouviu uma voz, lamentação e grande pranto: Raquel chorando os seus filhos, e não querendo ser consolada, porque eles já não existem.");
    b->dados[MATEUS].capitulos[2].versos[18] = wxT("Mas tendo morrido Herodes, eis que um anjo do Senhor apareceu em sonho a José no Egito,");
    b->dados[MATEUS].capitulos[2].versos[19] = wxT("dizendo: Levanta-te, toma o menino e sua mãe e vai para a terra de Israel; porque já morreram os que procuravam a morte do menino.");
    b->dados[MATEUS].capitulos[2].versos[20] = wxT("Então ele se levantou, tomou o menino e sua mãe e foi para a terra de Israel.");
    b->dados[MATEUS].capitulos[2].versos[21] = wxT("Ouvindo, porém, que Arquelau reinava na Judéia em lugar de seu pai Herodes, temeu ir para lá; mas avisado em sonho por divina revelação, retirou-se para as regiões da Galiléia,");
    b->dados[MATEUS].capitulos[2].versos[22] = wxT("e foi habitar numa cidade chamada Nazaré; para que se cumprisse o que fora dito pelos profetas: Ele será chamado nazareno.");

    b->dados[MATEUS].capitulos[3].versos[1] = wxT("Naqueles dias apareceu João, o Batista, pregando no deserto da Judéia,");
    b->dados[MATEUS].capitulos[3].versos[2] = wxT("dizendo: Arrependei-vos, porque é chegado o reino dos céus.");
    b->dados[MATEUS].capitulos[3].versos[3] = wxT("Porque este é o anunciado pelo profeta Isaías, que diz: Voz do que clama no deserto; Preparai o caminho do Senhor, endireitai as suas veredas.");
    b->dados[MATEUS].capitulos[3].versos[4] = wxT("Ora, João usava uma veste de pelos de camelo, e um cinto de couro em torno de seus lombos; e alimentava-se de gafanhotos e mel silvestre.");
    b->dados[MATEUS].capitulos[3].versos[5] = wxT("Então iam ter com ele os de Jerusalém, de toda a Judéia, e de toda a circunvizinhança do Jordão,");
    b->dados[MATEUS].capitulos[3].versos[6] = wxT("e eram por ele batizados no rio Jordão, confessando os seus pecados.");
    b->dados[MATEUS].capitulos[3].versos[7] = wxT("Mas, vendo ele muitos dos fariseus e dos saduceus que vinham ao seu batismo, disse-lhes: Raça de víboras, quem vos ensinou a fugir da ira vindoura?");
    b->dados[MATEUS].capitulos[3].versos[8] = wxT("Produzi, pois, frutos dignos de arrependimento,");
    b->dados[MATEUS].capitulos[3].versos[9] = wxT("e não queirais dizer dentro de vós mesmos: Temos por pai a Abraão; porque eu vos digo que mesmo destas pedras Deus pode suscitar filhos a Abraão.");
    b->dados[MATEUS].capitulos[3].versos[10] = wxT("E já está posto o machado á raiz das árvores; toda árvore, pois que não produz bom fruto, é cortada e lançada no fogo.");
    b->dados[MATEUS].capitulos[3].versos[11] = wxT("Eu, na verdade, vos batizo em água, na base do arrependimento; mas aquele que vem após mim é mais poderoso do que eu, que nem sou digno de levar-lhe as alparcas; ele vos batizará no Espírito Santo, e em fogo.");
    b->dados[MATEUS].capitulos[3].versos[12] = wxT("A sua pá ele tem na mão, e limpará bem a sua eira; recolherá o seu trigo ao celeiro, mas queimará a palha em fogo inextinguível.");
    b->dados[MATEUS].capitulos[3].versos[13] = wxT("Então veio Jesus da Galiléia ter com João, junto do Jordão, para ser batizado por ele.");
    b->dados[MATEUS].capitulos[3].versos[14] = wxT("Mas João o impedia, dizendo: Eu é que preciso ser batizado por ti, e tu vens a mim?");
    b->dados[MATEUS].capitulos[3].versos[15] = wxT("Jesus, porém, lhe respondeu: Consente agora; porque assim nos convém cumprir toda a justiça. Então ele consentiu.");
    b->dados[MATEUS].capitulos[3].versos[16] = wxT("Batizado que foi Jesus, saiu logo da água; e eis que se lhe abriram os céus, e viu o Espírito Santo de Deus descendo como uma pomba e vindo sobre ele;");
    b->dados[MATEUS].capitulos[3].versos[17] = wxT("e eis que uma voz dos céus dizia: Este é o meu Filho amado, em quem me comprazo.");

    b->dados[MATEUS].capitulos[4].versos[1] = wxT("Então foi conduzido Jesus pelo Espírito ao deserto, para ser tentado pelo Diabo.");
    b->dados[MATEUS].capitulos[4].versos[2] = wxT("E, tendo jejuado quarenta dias e quarenta noites, depois teve fome.");
    b->dados[MATEUS].capitulos[4].versos[3] = wxT("Chegando, então, o tentador, disse-lhe: Se tu és Filho de Deus manda que estas pedras se tornem em pães.");
    b->dados[MATEUS].capitulos[4].versos[4] = wxT("Mas Jesus lhe respondeu: Está escrito: Nem só de pão viverá o homem, mas de toda palavra que sai da boca de Deus.");
    b->dados[MATEUS].capitulos[4].versos[5] = wxT("Então o Diabo o levou à cidade santa, colocou-o sobre o pináculo do templo,");
    b->dados[MATEUS].capitulos[4].versos[6] = wxT("e disse-lhe: Se tu és Filho de Deus, lança-te daqui abaixo; porque está escrito: Aos seus anjos dará ordens a teu respeito; e: eles te susterão nas mãos, para que nunca tropeces em alguma pedra.");
    b->dados[MATEUS].capitulos[4].versos[7] = wxT("Replicou-lhe Jesus: Também está escrito: Não tentarás o Senhor teu Deus.");
    b->dados[MATEUS].capitulos[4].versos[8] = wxT("Novamente o Diabo o levou a um monte muito alto; e mostrou-lhe todos os reinos do mundo, e a glória deles;");
    b->dados[MATEUS].capitulos[4].versos[9] = wxT("e disse-lhe: Tudo isto te darei, se, prostrado, me adorares.");
    b->dados[MATEUS].capitulos[4].versos[10] = wxT("Então ordenou-lhe Jesus: Vai-te, Satanás; porque está escrito: Ao Senhor teu Deus adorarás, e só a ele servirás.");
    b->dados[MATEUS].capitulos[4].versos[11] = wxT("Então o Diabo o deixou; e eis que vieram os anjos e o serviram.");
    b->dados[MATEUS].capitulos[4].versos[12] = wxT("Ora, ouvindo Jesus que João fora entregue, retirou-se para a Galiléia;");
    b->dados[MATEUS].capitulos[4].versos[13] = wxT("e, deixando Nazaré, foi habitar em Cafarnaum, cidade marítima, nos confins de Zabulom e Naftali;");
    b->dados[MATEUS].capitulos[4].versos[14] = wxT("para que se cumprisse o que fora dito pelo profeta Isaías:");
    b->dados[MATEUS].capitulos[4].versos[15] = wxT("A terra de Zabulom e a terra de Naftali, o caminho do mar, além do Jordão, a Galiléia dos gentios,");
    b->dados[MATEUS].capitulos[4].versos[16] = wxT("o povo que estava sentado em trevas viu uma grande luz; sim, aos que estavam sentados na região da sombra da morte, a estes a luz raiou.");
    b->dados[MATEUS].capitulos[4].versos[17] = wxT("Desde então começou Jesus a pregar, e a dizer: Arrependei-vos, porque é chegado o reino dos céus.");
    b->dados[MATEUS].capitulos[4].versos[18] = wxT("E Jesus, andando ao longo do mar da Galiléia, viu dois irmãos - Simão, chamado Pedro, e seu irmão André, os quais lançavam a rede ao mar, porque eram pescadores.");
    b->dados[MATEUS].capitulos[4].versos[19] = wxT("Disse-lhes: Vinde após mim, e eu vos farei pescadores de homens.");
    b->dados[MATEUS].capitulos[4].versos[20] = wxT("Eles, pois, deixando imediatamente as redes, o seguiram.");
    b->dados[MATEUS].capitulos[4].versos[21] = wxT("E, passando mais adiante, viu outros dois irmãos - Tiago, filho de Zebedeu, e seu irmão João, no barco com seu pai Zebedeu, consertando as redes; e os chamou.");
    b->dados[MATEUS].capitulos[4].versos[22] = wxT("Estes, deixando imediatamente o barco e seu pai, seguiram-no.");
    b->dados[MATEUS].capitulos[4].versos[23] = wxT("E percorria Jesus toda a Galiléia, ensinando nas sinagogas, pregando o evangelho do reino, e curando todas as doenças e enfermidades entre o povo.");
    b->dados[MATEUS].capitulos[4].versos[24] = wxT("Assim a sua fama correu por toda a Síria; e trouxeram-lhe todos os que padeciam, acometidos de várias doenças e tormentos, os endemoninhados, os lunáticos, e os paralíticos; e ele os curou.");
    b->dados[MATEUS].capitulos[4].versos[25] = wxT("De sorte que o seguiam grandes multidões da Galiléia, de Decápolis, de Jerusalém, da Judéia, e dalém do Jordão.");

    b->dados[MATEUS].capitulos[5].versos[1] = wxT("Jesus, pois, vendo as multidões, subiu ao monte; e, tendo se assentado, aproximaram-se os seus discípulos,");
    b->dados[MATEUS].capitulos[5].versos[2] = wxT("e ele se pôs a ensiná-los, dizendo:");
    b->dados[MATEUS].capitulos[5].versos[3] = wxT("Bem-aventurados os humildes de espírito, porque deles é o reino dos céus.");
    b->dados[MATEUS].capitulos[5].versos[4] = wxT("Bem-aventurados os que choram, porque eles serão consolados.");
    b->dados[MATEUS].capitulos[5].versos[5] = wxT("Bem-aventurados os mansos, porque eles herdarão a terra.");
    b->dados[MATEUS].capitulos[5].versos[6] = wxT("Bem-aventurados os que têm fome e sede de justiça porque eles serão fartos.");
    b->dados[MATEUS].capitulos[5].versos[7] = wxT("Bem-aventurados os misericordiosos, porque eles alcançarão misericórdia.");
    b->dados[MATEUS].capitulos[5].versos[8] = wxT("Bem-aventurados os limpos de coração, porque eles verão a Deus.");
    b->dados[MATEUS].capitulos[5].versos[9] = wxT("Bem-aventurados os pacificadores, porque eles serão chamados filhos de Deus.");
    b->dados[MATEUS].capitulos[5].versos[10] = wxT("Bem-aventurados os que são perseguidos por causa da justiça, porque deles é o reino dos céus.");
    b->dados[MATEUS].capitulos[5].versos[11] = wxT("Bem-aventurados sois vós, quando vos injuriarem e perseguiram e, mentindo, disserem todo mal contra vós por minha causa.");
    b->dados[MATEUS].capitulos[5].versos[12] = wxT("Alegrai-vos e exultai, porque é grande o vosso galardão nos céus; porque assim perseguiram aos profetas que foram antes de vós.");
    b->dados[MATEUS].capitulos[5].versos[13] = wxT("Vós sois o sal da terra; mas se o sal se tornar insípido, com que se há de restaurar-lhe o sabor? para nada mais presta, senão para ser lançado fora, e ser pisado pelos homens.");
    b->dados[MATEUS].capitulos[5].versos[14] = wxT("Vós sois a luz do mundo. Não se pode esconder uma cidade situada sobre um monte;");
    b->dados[MATEUS].capitulos[5].versos[15] = wxT("nem os que acendem uma candeia a colocam debaixo do alqueire, mas no velador, e assim ilumina a todos que estão na casa.");
    b->dados[MATEUS].capitulos[5].versos[16] = wxT("Assim resplandeça a vossa luz diante dos homens, para que vejam as vossas boas obras, e glorifiquem a vosso Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[5].versos[17] = wxT("Não penseis que vim destruir a lei ou os profetas; não vim destruir, mas cumprir.");
    b->dados[MATEUS].capitulos[5].versos[18] = wxT("Porque em verdade vos digo que, até que o céu e a terra passem, de modo nenhum passará da lei um só i ou um só til, até que tudo seja cumprido.");
    b->dados[MATEUS].capitulos[5].versos[19] = wxT("Qualquer, pois, que violar um destes mandamentos, por menor que seja, e assim ensinar aos homens, será chamado o menor no reino dos céus; aquele, porém, que os cumprir e ensinar será chamado grande no reino dos céus.");
    b->dados[MATEUS].capitulos[5].versos[20] = wxT("Pois eu vos digo que, se a vossa justiça não exceder a dos escribas e fariseus, de modo nenhum entrareis no reino dos céus.");
    b->dados[MATEUS].capitulos[5].versos[21] = wxT("Ouvistes que foi dito aos antigos: Não matarás; e, Quem matar será réu de juízo.");
    b->dados[MATEUS].capitulos[5].versos[22] = wxT("Eu, porém, vos digo que todo aquele que se encolerizar contra seu irmão, será réu de juízo; e quem disser a seu irmão: Raca, será réu diante do sinédrio; e quem lhe disser: Tolo, será réu do fogo do inferno.");
    b->dados[MATEUS].capitulos[5].versos[23] = wxT("Portanto, se estiveres apresentando a tua oferta no altar, e aí te lembrares de que teu irmão tem alguma coisa contra ti,");
    b->dados[MATEUS].capitulos[5].versos[24] = wxT("deixa ali diante do altar a tua oferta, e vai conciliar-te primeiro com teu irmão, e depois vem apresentar a tua oferta.");
    b->dados[MATEUS].capitulos[5].versos[25] = wxT("Concilia-te depressa com o teu adversário, enquanto estás no caminho com ele; para que não aconteça que o adversário te entregue ao guarda, e sejas lançado na prisão.");
    b->dados[MATEUS].capitulos[5].versos[26] = wxT("Em verdade te digo que de maneira nenhuma sairás dali enquanto não pagares o último ceitil.");
    b->dados[MATEUS].capitulos[5].versos[27] = wxT("Ouvistes que foi dito: Não adulterarás.");
    b->dados[MATEUS].capitulos[5].versos[28] = wxT("Eu, porém, vos digo que todo aquele que olhar para uma mulher para a cobiçar, já em seu coração cometeu adultério com ela.");
    b->dados[MATEUS].capitulos[5].versos[29] = wxT("Se o teu olho direito te faz tropeçar, arranca-o e lança-o de ti; pois te é melhor que se perca um dos teus membros do que seja todo o teu corpo lançado no inferno.");
    b->dados[MATEUS].capitulos[5].versos[30] = wxT("E, se a tua mão direita te faz tropeçar, corta-a e lança-a de ti; pois te é melhor que se perca um dos teus membros do que vá todo o teu corpo para o inferno.");
    b->dados[MATEUS].capitulos[5].versos[31] = wxT("Também foi dito: Quem repudiar sua mulher, dê-lhe carta de divórcio.");
    b->dados[MATEUS].capitulos[5].versos[32] = wxT("Eu, porém, vos digo que todo aquele que repudia sua mulher, a não ser por causa de infidelidade, a faz adúltera; e quem casar com a repudiada, comete adultério.");
    b->dados[MATEUS].capitulos[5].versos[33] = wxT("Outrossim, ouvistes que foi dito aos antigos: Não jurarás falso, mas cumprirás para com o Senhor os teus juramentos.");
    b->dados[MATEUS].capitulos[5].versos[34] = wxT("Eu, porém, vos digo que de maneira nenhuma jureis; nem pelo céu, porque é o trono de Deus;");
    b->dados[MATEUS].capitulos[5].versos[35] = wxT("nem pela terra, porque é o escabelo de seus pés; nem por Jerusalém, porque é a cidade do grande Rei;");
    b->dados[MATEUS].capitulos[5].versos[36] = wxT("nem jures pela tua cabeça, porque não podes tornar um só cabelo branco ou preto.");
    b->dados[MATEUS].capitulos[5].versos[37] = wxT("Seja, porém, o vosso falar: Sim, sim; não, não; pois o que passa daí, vem do Maligno.");
    b->dados[MATEUS].capitulos[5].versos[38] = wxT("Ouvistes que foi dito: Olho por olho, e dente por dente.");
    b->dados[MATEUS].capitulos[5].versos[39] = wxT("Eu, porém, vos digo que não resistais ao homem mau; mas a qualquer que te bater na face direita, oferece-lhe também a outra;");
    b->dados[MATEUS].capitulos[5].versos[40] = wxT("e ao que quiser pleitear contigo, e tirar-te a túnica, larga-lhe também a capa;");
    b->dados[MATEUS].capitulos[5].versos[41] = wxT("e, se qualquer te obrigar a caminhar mil passos, vai com ele dois mil.");
    b->dados[MATEUS].capitulos[5].versos[42] = wxT("Dá a quem te pedir, e não voltes as costas ao que quiser que lhe emprestes.");
    b->dados[MATEUS].capitulos[5].versos[43] = wxT("Ouvistes que foi dito: Amarás ao teu próximo, e odiarás ao teu inimigo.");
    b->dados[MATEUS].capitulos[5].versos[44] = wxT("Eu, porém, vos digo: Amai aos vossos inimigos, e orai pelos que vos perseguem;");
    b->dados[MATEUS].capitulos[5].versos[45] = wxT("para que vos torneis filhos do vosso Pai que está nos céus; porque ele faz nascer o seu sol sobre maus e bons, e faz chover sobre justos e injustos.");
    b->dados[MATEUS].capitulos[5].versos[46] = wxT("Pois, se amardes aos que vos amam, que recompensa tereis? não fazem os publicanos também o mesmo?");
    b->dados[MATEUS].capitulos[5].versos[47] = wxT("E, se saudardes somente os vossos irmãos, que fazeis demais? não fazem os gentios também o mesmo?");
    b->dados[MATEUS].capitulos[5].versos[48] = wxT("Sede vós, pois, perfeitos, como é perfeito o vosso Pai celestial.");

    b->dados[MATEUS].capitulos[6].versos[1] = wxT("Guardai-vos de fazer as vossas boas obras diante dos homens, para serdes vistos por eles; de outra sorte não tereis recompensa junto de vosso Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[6].versos[2] = wxT("Quando, pois, deres esmola, não faças tocar trombeta diante de ti, como fazem os hipócritas nas sinagogas e nas ruas, para serem glorificados pelos homens. Em verdade vos digo que já receberam a sua recompensa.");
    b->dados[MATEUS].capitulos[6].versos[3] = wxT("Mas, quando tu deres esmola, não saiba a tua mão esquerda o que faz a direita;");
    b->dados[MATEUS].capitulos[6].versos[4] = wxT("para que a tua esmola fique em secreto; e teu Pai, que vê em secreto, te recompensará.");
    b->dados[MATEUS].capitulos[6].versos[5] = wxT("E, quando orardes, não sejais como os hipócritas; pois gostam de orar em pé nas sinagogas, e às esquinas das ruas, para serem vistos pelos homens. Em verdade vos digo que já receberam a sua recompensa.");
    b->dados[MATEUS].capitulos[6].versos[6] = wxT("Mas tu, quando orares, entra no teu quarto e, fechando a porta, ora a teu Pai que está em secreto; e teu Pai, que vê em secreto, te recompensará.");
    b->dados[MATEUS].capitulos[6].versos[7] = wxT("E, orando, não useis de vãs repetições, como os gentios; porque pensam que pelo seu muito falar serão ouvidos.");
    b->dados[MATEUS].capitulos[6].versos[8] = wxT("Não vos assemelheis, pois, a eles; porque vosso Pai sabe o que vos é necessário, antes de vós lho pedirdes.");
    b->dados[MATEUS].capitulos[6].versos[9] = wxT("Portanto, orai vós deste modo: Pai nosso que estás nos céus, santificado seja o teu nome;");
    b->dados[MATEUS].capitulos[6].versos[10] = wxT("venha o teu reino, seja feita a tua vontade, assim na terra como no céu;");
    b->dados[MATEUS].capitulos[6].versos[11] = wxT("o pão nosso de cada dia nos dá hoje;");
    b->dados[MATEUS].capitulos[6].versos[12] = wxT("e perdoa-nos as nossas dívidas, assim como nós também temos perdoado aos nossos devedores;");
    b->dados[MATEUS].capitulos[6].versos[13] = wxT("e não nos deixes entrar em tentação; mas livra-nos do mal. {Porque teu é o reino e o poder, e a glória, para sempre, Amém.}");
    b->dados[MATEUS].capitulos[6].versos[14] = wxT("Porque, se perdoardes aos homens as suas ofensas, também vosso Pai celestial vos perdoará a vós;");
    b->dados[MATEUS].capitulos[6].versos[15] = wxT("se, porém, não perdoardes aos homens, tampouco vosso Pai perdoará vossas ofensas.");
    b->dados[MATEUS].capitulos[6].versos[16] = wxT("Quando jejuardes, não vos mostreis contristados como os hipócritas; porque eles desfiguram os seus rostos, para que os homens vejam que estão jejuando. Em verdade vos digo que já receberam a sua recompensa.");
    b->dados[MATEUS].capitulos[6].versos[17] = wxT("Tu, porém, quando jejuares, unge a tua cabeça, e lava o teu rosto,");
    b->dados[MATEUS].capitulos[6].versos[18] = wxT("para não mostrar aos homens que estás jejuando, mas a teu Pai, que está em secreto; e teu Pai, que vê em secreto, te recompensará.");
    b->dados[MATEUS].capitulos[6].versos[19] = wxT("Não ajunteis para vós tesouros na terra; onde a traça e a ferrugem os consomem, e onde os ladrões minam e roubam;");
    b->dados[MATEUS].capitulos[6].versos[20] = wxT("mas ajuntai para vós tesouros no céu, onde nem a traça nem a ferrugem os consumem, e onde os ladrões não minam nem roubam.");
    b->dados[MATEUS].capitulos[6].versos[21] = wxT("Porque onde estiver o teu tesouro, aí estará também o teu coração.");
    b->dados[MATEUS].capitulos[6].versos[22] = wxT("A candeia do corpo são os olhos; de sorte que, se os teus olhos forem bons, todo teu corpo terá luz;");
    b->dados[MATEUS].capitulos[6].versos[23] = wxT("se, porém, os teus olhos forem maus, o teu corpo será tenebroso. Se, portanto, a luz que em ti há são trevas, quão grandes são tais trevas!");
    b->dados[MATEUS].capitulos[6].versos[24] = wxT("Ninguém pode servir a dois senhores; porque ou há de odiar a um e amar o outro, ou há de dedicar-se a um e desprezar o outro. Não podeis servir a Deus e às riquezas.");
    b->dados[MATEUS].capitulos[6].versos[25] = wxT("Por isso vos digo: Não estejais ansiosos quanto à vossa vida, pelo que haveis de comer, ou pelo que haveis de beber; nem, quanto ao vosso corpo, pelo que haveis de vestir. Não é a vida mais do que o alimento, e o corpo mais do que o vestuário?");
    b->dados[MATEUS].capitulos[6].versos[26] = wxT("Olhai para as aves do céu, que não semeiam, nem ceifam, nem ajuntam em celeiros; e vosso Pai celestial as alimenta. Não valeis vós muito mais do que elas?");
    b->dados[MATEUS].capitulos[6].versos[27] = wxT("Ora, qual de vós, por mais ansioso que esteja, pode acrescentar um côvado à sua estatura?");
    b->dados[MATEUS].capitulos[6].versos[28] = wxT("E pelo que haveis de vestir, por que andais ansiosos? Olhai para os lírios do campo, como crescem; não trabalham nem fiam;");
    b->dados[MATEUS].capitulos[6].versos[29] = wxT("contudo vos digo que nem mesmo Salomão em toda a sua glória se vestiu como um deles.");
    b->dados[MATEUS].capitulos[6].versos[30] = wxT("Pois, se Deus assim veste a erva do campo, que hoje existe e amanhã é lançada no forno, quanto mais a vós, homens de pouca fé?");
    b->dados[MATEUS].capitulos[6].versos[31] = wxT("Portanto, não vos inquieteis, dizendo: Que havemos de comer? ou: Que havemos de beber? ou: Com que nos havemos de vestir?");
    b->dados[MATEUS].capitulos[6].versos[32] = wxT("{Pois a todas estas coisas os gentios procuram.} Porque vosso Pai celestial sabe que precisais de tudo isso.");
    b->dados[MATEUS].capitulos[6].versos[33] = wxT("Mas buscai primeiro o seu reino e a sua justiça, e todas estas coisas vos serão acrescentadas.");
    b->dados[MATEUS].capitulos[6].versos[34] = wxT("Não vos inquieteis, pois, pelo dia de amanhã; porque o dia de amanhã cuidará de si mesmo. Basta a cada dia o seu mal.");

    b->dados[MATEUS].capitulos[7].versos[1] = wxT("Não julgueis, para que não sejais julgados.");
    b->dados[MATEUS].capitulos[7].versos[2] = wxT("Porque com o juízo com que julgais, sereis julgados; e com a medida com que medis vos medirão a vós.");
    b->dados[MATEUS].capitulos[7].versos[3] = wxT("E por que vês o argueiro no olho do teu irmão, e não reparas na trave que está no teu olho?");
    b->dados[MATEUS].capitulos[7].versos[4] = wxT("Ou como dirás a teu irmão: Deixa-me tirar o argueiro do teu olho, quando tens a trave no teu?");
    b->dados[MATEUS].capitulos[7].versos[5] = wxT("Hipócrita! tira primeiro a trave do teu olho; e então verás bem para tirar o argueiro do olho do teu irmão.");
    b->dados[MATEUS].capitulos[7].versos[6] = wxT("Não deis aos cães o que é santo, nem lanceis aos porcos as vossas pérolas, para não acontecer que as calquem aos pés e, voltando-se, vos despedacem.");
    b->dados[MATEUS].capitulos[7].versos[7] = wxT("Pedí, e dar-se-vos-á; buscai, e achareis; batei e abrir-se-vos-á.");
    b->dados[MATEUS].capitulos[7].versos[8] = wxT("Pois todo o que pede, recebe; e quem busca, acha; e ao que bate, abrir-se-lhe-á.");
    b->dados[MATEUS].capitulos[7].versos[9] = wxT("Ou qual dentre vós é o homem que, se seu filho lhe pedir pão, lhe dará uma pedra?");
    b->dados[MATEUS].capitulos[7].versos[10] = wxT("Ou, se lhe pedir peixe, lhe dará uma serpente?");
    b->dados[MATEUS].capitulos[7].versos[11] = wxT("Se vós, pois, sendo maus, sabeis dar boas dádivas a vossos filhos, quanto mais vosso Pai, que está nos céus, dará boas coisas aos que lhas pedirem?");
    b->dados[MATEUS].capitulos[7].versos[12] = wxT("Portanto, tudo o que vós quereis que os homens vos façam, fazei-lho também vós a eles; porque esta é a lei e os profetas.");
    b->dados[MATEUS].capitulos[7].versos[13] = wxT("Entrai pela porta estreita; porque larga é a porta, e espaçoso o caminho que conduz à perdição, e muitos são os que entram por ela;");
    b->dados[MATEUS].capitulos[7].versos[14] = wxT("e porque estreita é a porta, e apertado o caminho que conduz à vida, e poucos são os que a encontram.");
    b->dados[MATEUS].capitulos[7].versos[15] = wxT("Guardai-vos dos falsos profetas, que vêm a vós disfarçados em ovelhas, mas interiormente são lobos devoradores.");
    b->dados[MATEUS].capitulos[7].versos[16] = wxT("Pelos seus frutos os conhecereis. Colhem-se, porventura, uvas dos espinheiros, ou figos dos abrolhos?");
    b->dados[MATEUS].capitulos[7].versos[17] = wxT("Assim, toda árvore boa produz bons frutos; porém a árvore má produz frutos maus.");
    b->dados[MATEUS].capitulos[7].versos[18] = wxT("Uma árvore boa não pode dar maus frutos; nem uma árvore má dar frutos bons.");
    b->dados[MATEUS].capitulos[7].versos[19] = wxT("Toda árvore que não produz bom fruto é cortada e lançada no fogo.");
    b->dados[MATEUS].capitulos[7].versos[20] = wxT("Portanto, pelos seus frutos os conhecereis.");
    b->dados[MATEUS].capitulos[7].versos[21] = wxT("Nem todo o que me diz: Senhor, Senhor! entrará no reino dos céus, mas aquele que faz a vontade de meu Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[7].versos[22] = wxT("Muitos me dirão naquele dia: Senhor, Senhor, não profetizamos nós em teu nome? e em teu nome não expulsamos demônios? e em teu nome não fizemos muitos milagres?");
    b->dados[MATEUS].capitulos[7].versos[23] = wxT("Então lhes direi claramente: Nunca vos conheci; apartai-vos de mim, vós que praticais a iniqüidade.");
    b->dados[MATEUS].capitulos[7].versos[24] = wxT("Todo aquele, pois, que ouve estas minhas palavras e as põe em prática, será comparado a um homem prudente, que edificou a casa sobre a rocha.");
    b->dados[MATEUS].capitulos[7].versos[25] = wxT("E desceu a chuva, correram as torrentes, sopraram os ventos, e bateram com ímpeto contra aquela casa; contudo não caiu, porque estava fundada sobre a rocha.");
    b->dados[MATEUS].capitulos[7].versos[26] = wxT("Mas todo aquele que ouve estas minhas palavras, e não as põe em prática, será comparado a um homem insensato, que edificou a sua casa sobre a areia.");
    b->dados[MATEUS].capitulos[7].versos[27] = wxT("E desceu a chuva, correram as torrentes, sopraram os ventos, e bateram com ímpeto contra aquela casa, e ela caiu; e grande foi a sua queda.");
    b->dados[MATEUS].capitulos[7].versos[28] = wxT("Ao concluir Jesus este discurso, as multidões se maravilhavam da sua doutrina;");
    b->dados[MATEUS].capitulos[7].versos[29] = wxT("porque as ensinava como tendo autoridade, e não como os escribas.");

    b->dados[MATEUS].capitulos[8].versos[1] = wxT("Quando Jesus desceu do monte, grandes multidões o seguiam.");
    b->dados[MATEUS].capitulos[8].versos[2] = wxT("E eis que veio um leproso e o adorava, dizendo: Senhor, se quiseres, podes tornar-me limpo.");
    b->dados[MATEUS].capitulos[8].versos[3] = wxT("Jesus, pois, estendendo a mão, tocou-o, dizendo: Quero; sê limpo. No mesmo instante ficou purificado da sua lepra.");
    b->dados[MATEUS].capitulos[8].versos[4] = wxT("Disse-lhe então Jesus: Olha, não contes isto a ninguém; mas vai, mostra-te ao sacerdote, e apresenta a oferta que Moisés determinou, para lhes servir de testemunho.");
    b->dados[MATEUS].capitulos[8].versos[5] = wxT("Tendo Jesus entrado em Cafarnaum, chegou-se a ele um centurião que lhe rogava, dizendo:");
    b->dados[MATEUS].capitulos[8].versos[6] = wxT("Senhor, o meu criado jaz em casa paralítico, e horrivelmente atormentado.");
    b->dados[MATEUS].capitulos[8].versos[7] = wxT("Respondeu-lhe Jesus: Eu irei, e o curarei.");
    b->dados[MATEUS].capitulos[8].versos[8] = wxT("O centurião, porém, replicou-lhe: Senhor, não sou digno de que entres debaixo do meu telhado; mas somente dize uma palavra, e o meu criado há de sarar.");
    b->dados[MATEUS].capitulos[8].versos[9] = wxT("Pois também eu sou homem sujeito à autoridade, e tenho soldados às minhas ordens; e digo a este: Vai, e ele vai; e a outro: Vem, e ele vem; e ao meu servo: Faze isto, e ele o faz.");
    b->dados[MATEUS].capitulos[8].versos[10] = wxT("Jesus, ouvindo isso, admirou-se, e disse aos que o seguiam: Em verdade vos digo que a ninguém encontrei em Israel com tamanha fé.");
    b->dados[MATEUS].capitulos[8].versos[11] = wxT("Também vos digo que muitos virão do oriente e do ocidente, e reclinar-se-ão à mesa de Abraão, Isaque e Jacó, no reino dos céus;");
    b->dados[MATEUS].capitulos[8].versos[12] = wxT("mas os filhos do reino serão lançados nas trevas exteriores; ali haverá choro e ranger de dentes.");
    b->dados[MATEUS].capitulos[8].versos[13] = wxT("Então disse Jesus ao centurião: Vai-te, e te seja feito assim como creste. E naquela mesma hora o seu criado sarou.");
    b->dados[MATEUS].capitulos[8].versos[14] = wxT("Ora, tendo Jesus entrado na casa de Pedro, viu a sogra deste de cama; e com febre.");
    b->dados[MATEUS].capitulos[8].versos[15] = wxT("E tocou-lhe a mão, e a febre a deixou; então ela se levantou, e o servia.");
    b->dados[MATEUS].capitulos[8].versos[16] = wxT("Caída a tarde, trouxeram-lhe muitos endemoninhados; e ele com a sua palavra expulsou os espíritos, e curou todos os enfermos;");
    b->dados[MATEUS].capitulos[8].versos[17] = wxT("para que se cumprisse o que fora dito pelo profeta Isaías: Ele tomou sobre si as nossas enfermidades, e levou as nossas doenças.");
    b->dados[MATEUS].capitulos[8].versos[18] = wxT("Vendo Jesus uma multidão ao redor de si, deu ordem de partir para o outro lado do mar.");
    b->dados[MATEUS].capitulos[8].versos[19] = wxT("E, aproximando-se um escriba, disse-lhe: Mestre, seguir-te-ei para onde quer que fores.");
    b->dados[MATEUS].capitulos[8].versos[20] = wxT("Respondeu-lhe Jesus: As raposas têm covis, e as aves do céu têm ninhos; mas o Filho do homem não tem onde reclinar a cabeça.");
    b->dados[MATEUS].capitulos[8].versos[21] = wxT("E outro de seus discípulos lhe disse: Senhor, permite-me ir primeiro sepultar meu pai.");
    b->dados[MATEUS].capitulos[8].versos[22] = wxT("Jesus, porém, respondeu-lhe: Segue-me, e deixa os mortos sepultar os seus próprios mortos.");
    b->dados[MATEUS].capitulos[8].versos[23] = wxT("E, entrando ele no barco, seus discípulos o seguiram.");
    b->dados[MATEUS].capitulos[8].versos[24] = wxT("E eis que se levantou no mar tão grande tempestade que o barco era coberto pelas ondas; ele, porém, estava dormindo.");
    b->dados[MATEUS].capitulos[8].versos[25] = wxT("Os discípulos, pois, aproximando-se, o despertaram, dizendo: Salva-nos, Senhor, que estamos perecendo.");
    b->dados[MATEUS].capitulos[8].versos[26] = wxT("Ele lhes respondeu: Por que temeis, homens de pouca fé? Então, levantando-se repreendeu os ventos e o mar, e seguiu-se grande bonança.");
    b->dados[MATEUS].capitulos[8].versos[27] = wxT("E aqueles homens se maravilharam, dizendo: Que homem é este, que até os ventos e o mar lhe obedecem?");
    b->dados[MATEUS].capitulos[8].versos[28] = wxT("Tendo ele chegado ao outro lado, à terra dos gadarenos, saíram-lhe ao encontro dois endemoninhados, vindos dos sepulcros; tão ferozes eram que ninguém podia passar por aquele caminho.");
    b->dados[MATEUS].capitulos[8].versos[29] = wxT("E eis que gritaram, dizendo: Que temos nós contigo, Filho de Deus? Vieste aqui atormentar-nos antes do tempo?");
    b->dados[MATEUS].capitulos[8].versos[30] = wxT("Ora, a alguma distância deles, andava pastando uma grande manada de porcos.");
    b->dados[MATEUS].capitulos[8].versos[31] = wxT("E os demônios rogavam-lhe, dizendo: Se nos expulsas, manda-nos entrar naquela manada de porcos.");
    b->dados[MATEUS].capitulos[8].versos[32] = wxT("Disse-lhes Jesus: Ide. Então saíram, e entraram nos porcos; e eis que toda a manada se precipitou pelo despenhadeiro no mar, perecendo nas águas.");
    b->dados[MATEUS].capitulos[8].versos[33] = wxT("Os pastores fugiram e, chegando à cidade, divulgaram todas estas coisas, e o que acontecera aos endemoninhados.");
    b->dados[MATEUS].capitulos[8].versos[34] = wxT("E eis que toda a cidade saiu ao encontro de Jesus; e vendo-o, rogaram-lhe que se retirasse dos seus termos.");

    b->dados[MATEUS].capitulos[9].versos[1] = wxT("E entrando Jesus num barco, passou para o outro lado, e chegou à sua própria cidade.");
    b->dados[MATEUS].capitulos[9].versos[2] = wxT("E eis que lhe trouxeram um paralítico deitado num leito. Jesus, pois, vendo-lhes a fé, disse ao paralítico: Tem ânimo, filho; perdoados são os teus pecados.");
    b->dados[MATEUS].capitulos[9].versos[3] = wxT("E alguns dos escribas disseram consigo: Este homem blasfema.");
    b->dados[MATEUS].capitulos[9].versos[4] = wxT("Mas Jesus, conhecendo-lhes os pensamentos, disse: Por que pensais o mal em vossos corações?");
    b->dados[MATEUS].capitulos[9].versos[5] = wxT("Pois qual é mais fácil? dizer: Perdoados são os teus pecados, ou dizer: Levanta-te e anda?");
    b->dados[MATEUS].capitulos[9].versos[6] = wxT("Ora, para que saibais que o Filho do homem tem sobre a terra autoridade para perdoar pecados {disse então ao paralítico}: Levanta-te, toma o teu leito, e vai para tua casa.");
    b->dados[MATEUS].capitulos[9].versos[7] = wxT("E este, levantando-se, foi para sua casa.");
    b->dados[MATEUS].capitulos[9].versos[8] = wxT("E as multidões, vendo isso, temeram, e glorificaram a Deus, que dera tal autoridade aos homens.");
    b->dados[MATEUS].capitulos[9].versos[9] = wxT("Partindo Jesus dali, viu sentado na coletoria um homem chamado Mateus, e disse-lhe: Segue-me. E ele, levantando-se, o seguiu.");
    b->dados[MATEUS].capitulos[9].versos[10] = wxT("Ora, estando ele à mesa em casa, eis que chegaram muitos publicanos e pecadores, e se reclinaram à mesa juntamente com Jesus e seus discípulos.");
    b->dados[MATEUS].capitulos[9].versos[11] = wxT("E os fariseus, vendo isso, perguntavam aos discípulos: Por que come o vosso Mestre com publicanos e pecadores?");
    b->dados[MATEUS].capitulos[9].versos[12] = wxT("Jesus, porém, ouvindo isso, respondeu: Não necessitam de médico os sãos, mas sim os enfermos.");
    b->dados[MATEUS].capitulos[9].versos[13] = wxT("Ide, pois, e aprendei o que significa: Misericórdia quero, e não sacrifícios. Porque eu não vim chamar justos, mas pecadores.");
    b->dados[MATEUS].capitulos[9].versos[14] = wxT("Então vieram ter com ele os discípulos de João, perguntando: Por que é que nós e os fariseus jejuamos, mas os teus discípulos não jejuam?");
    b->dados[MATEUS].capitulos[9].versos[15] = wxT("Respondeu-lhes Jesus: Podem porventura ficar tristes os convidados às núpcias, enquanto o noivo está com eles? Dias virão, porém, em que lhes será tirado o noivo, e então hão de jejuar.");
    b->dados[MATEUS].capitulos[9].versos[16] = wxT("Ninguém põe remendo de pano novo em vestido velho; porque semelhante remendo tira parte do vestido, e faz-se maior a rotura.");
    b->dados[MATEUS].capitulos[9].versos[17] = wxT("Nem se deita vinho novo em odres velhos; do contrário se rebentam, derrama-se o vinho, e os odres se perdem; mas deita-se vinho novo em odres novos, e assim ambos se conservam.");
    b->dados[MATEUS].capitulos[9].versos[18] = wxT("Enquanto ainda lhes dizia essas coisas, eis que chegou um chefe da sinagoga e o adorou, dizendo: Minha filha acaba de falecer; mas vem, impõe-lhe a tua mão, e ela viverá.");
    b->dados[MATEUS].capitulos[9].versos[19] = wxT("Levantou-se, pois, Jesus, e o foi seguindo, ele e os seus discípulos.");
    b->dados[MATEUS].capitulos[9].versos[20] = wxT("E eis que certa mulher, que havia doze anos padecia de uma hemorragia, chegou por detrás dele e tocou-lhe a orla do manto;");
    b->dados[MATEUS].capitulos[9].versos[21] = wxT("porque dizia consigo: Se eu tão-somente tocar-lhe o manto, ficarei sã.");
    b->dados[MATEUS].capitulos[9].versos[22] = wxT("Mas Jesus, voltando-se e vendo-a, disse: Tem ânimo, filha, a tua fé te salvou. E desde aquela hora a mulher ficou sã.");
    b->dados[MATEUS].capitulos[9].versos[23] = wxT("Quando Jesus chegou à casa daquele chefe, e viu os tocadores de flauta e a multidão em alvoroço,");
    b->dados[MATEUS].capitulos[9].versos[24] = wxT("disse; Retirai-vos; porque a menina não está morta, mas dorme. E riam-se dele.");
    b->dados[MATEUS].capitulos[9].versos[25] = wxT("Tendo-se feito sair o povo, entrou Jesus, tomou a menina pela mão, e ela se levantou.");
    b->dados[MATEUS].capitulos[9].versos[26] = wxT("E espalhou-se a notícia disso por toda aquela terra.");
    b->dados[MATEUS].capitulos[9].versos[27] = wxT("Partindo Jesus dali, seguiram-no dois cegos, que clamavam, dizendo: Tem compaixão de nós, Filho de Davi.");
    b->dados[MATEUS].capitulos[9].versos[28] = wxT("E, tendo ele entrado em casa, os cegos se aproximaram dele; e Jesus perguntou-lhes: Credes que eu posso fazer isto? Responderam-lhe eles: Sim, Senhor.");
    b->dados[MATEUS].capitulos[9].versos[29] = wxT("Então lhes tocou os olhos, dizendo: Seja-vos feito segundo a vossa fé.");
    b->dados[MATEUS].capitulos[9].versos[30] = wxT("E os olhos se lhes abriram. Jesus ordenou-lhes terminantemente, dizendo: Vede que ninguém o saiba.");
    b->dados[MATEUS].capitulos[9].versos[31] = wxT("Eles, porém, saíram, e divulgaram a sua fama por toda aquela terra.");
    b->dados[MATEUS].capitulos[9].versos[32] = wxT("Enquanto esses se retiravam, eis que lhe trouxeram um homem mudo e endemoninhado.");
    b->dados[MATEUS].capitulos[9].versos[33] = wxT("E, expulso o demônio, falou o mudo e as multidões se admiraram, dizendo: Nunca tal se viu em Israel.");
    b->dados[MATEUS].capitulos[9].versos[34] = wxT("Os fariseus, porém, diziam: É pelo príncipe dos demônios que ele expulsa os demônios.");
    b->dados[MATEUS].capitulos[9].versos[35] = wxT("E percorria Jesus todas as cidades e aldeias, ensinando nas sinagogas, pregando o evangelho do reino, e curando toda sorte de doenças e enfermidades.");
    b->dados[MATEUS].capitulos[9].versos[36] = wxT("Vendo ele as multidões, compadeceu-se delas, porque andavam desgarradas e errantes, como ovelhas que não têm pastor.");
    b->dados[MATEUS].capitulos[9].versos[37] = wxT("Então disse a seus discípulos: Na verdade, a seara é grande, mas os trabalhadores são poucos.");
    b->dados[MATEUS].capitulos[9].versos[38] = wxT("Rogai, pois, ao Senhor da seara que mande trabalhadores para a sua seara.");

    b->dados[MATEUS].capitulos[10].versos[1] = wxT("E, chamando a si os seus doze discípulos, deu-lhes autoridade sobre os espíritos imundos, para expulsarem, e para curarem toda sorte de doenças e enfermidades.");
    b->dados[MATEUS].capitulos[10].versos[2] = wxT("Ora, os nomes dos doze apóstolos são estes: primeiro, Simão, chamado Pedro, e André, seu irmão; Tiago, filho de Zebedeu, e João, seu irmão;");
    b->dados[MATEUS].capitulos[10].versos[3] = wxT("Felipe e Bartolomeu; Tomé e Mateus, o publicano; Tiago, filho de Alfeu, e Tadeu;");
    b->dados[MATEUS].capitulos[10].versos[4] = wxT("Simão Cananeu, e Judas Iscariotes, aquele que o traiu.");
    b->dados[MATEUS].capitulos[10].versos[5] = wxT("A estes doze enviou Jesus, e ordenou-lhes, dizendo: Não ireis aos gentios, nem entrareis em cidade de samaritanos;");
    b->dados[MATEUS].capitulos[10].versos[6] = wxT("mas ide antes às ovelhas perdidas da casa de Israel;");
    b->dados[MATEUS].capitulos[10].versos[7] = wxT("e indo, pregai, dizendo: É chegado o reino dos céus.");
    b->dados[MATEUS].capitulos[10].versos[8] = wxT("Curai os enfermos, ressuscitai os mortos, limpai os leprosos, expulsai os demônios; de graça recebestes, de graça dai.");
    b->dados[MATEUS].capitulos[10].versos[9] = wxT("Não vos provereis de ouro, nem de prata, nem de cobre, em vossos cintos;");
    b->dados[MATEUS].capitulos[10].versos[10] = wxT("nem de alforje para o caminho, nem de duas túnicas, nem de alparcas, nem de bordão; porque digno é o trabalhador do seu alimento.");
    b->dados[MATEUS].capitulos[10].versos[11] = wxT("Em qualquer cidade ou aldeia em que entrardes, procurai saber quem nela é digno, e hospedai-vos aí até que vos retireis.");
    b->dados[MATEUS].capitulos[10].versos[12] = wxT("E, ao entrardes na casa, saudai-a;");
    b->dados[MATEUS].capitulos[10].versos[13] = wxT("se a casa for digna, desça sobre ela a vossa paz; mas, se não for digna, torne para vós a vossa paz.");
    b->dados[MATEUS].capitulos[10].versos[14] = wxT("E, se ninguém vos receber, nem ouvir as vossas palavras, saindo daquela casa ou daquela cidade, sacudi o pó dos vossos pés.");
    b->dados[MATEUS].capitulos[10].versos[15] = wxT("Em verdade vos digo que, no dia do juízo, haverá menos rigor para a terra de Sodoma e Gomorra do que para aquela cidade.");
    b->dados[MATEUS].capitulos[10].versos[16] = wxT("Eis que vos envio como ovelhas ao meio de lobos; portanto, sede prudentes como as serpentes e simples como as pombas.");
    b->dados[MATEUS].capitulos[10].versos[17] = wxT("Acautelai-vos dos homens; porque eles vos entregarão aos sinédrios, e vos açoitarão nas suas sinagogas;");
    b->dados[MATEUS].capitulos[10].versos[18] = wxT("e por minha causa sereis levados à presença dos governadores e dos reis, para lhes servir de testemunho, a eles e aos gentios.");
    b->dados[MATEUS].capitulos[10].versos[19] = wxT("Mas, quando vos entregarem, não cuideis de como, ou o que haveis de falar; porque naquela hora vos será dado o que haveis de dizer.");
    b->dados[MATEUS].capitulos[10].versos[20] = wxT("Porque não sois vós que falais, mas o Espírito de vosso Pai é que fala em vós.");
    b->dados[MATEUS].capitulos[10].versos[21] = wxT("Um irmão entregará à morte a seu irmão, e um pai a seu filho; e filhos se levantarão contra os pais e os matarão.");
    b->dados[MATEUS].capitulos[10].versos[22] = wxT("E sereis odiados de todos por causa do meu nome, mas aquele que perseverar até o fim, esse será salvo.");
    b->dados[MATEUS].capitulos[10].versos[23] = wxT("Quando, porém, vos perseguirem numa cidade, fugi para outra; porque em verdade vos digo que não acabareis de percorrer as cidades de Israel antes que venha o Filho do homem.");
    b->dados[MATEUS].capitulos[10].versos[24] = wxT("Não é o discípulo mais do que o seu mestre, nem o servo mais do que o seu senhor.");
    b->dados[MATEUS].capitulos[10].versos[25] = wxT("Basta ao discípulo ser como seu mestre, e ao servo como seu senhor. Se chamaram Belzebu ao dono da casa, quanto mais aos seus domésticos?");
    b->dados[MATEUS].capitulos[10].versos[26] = wxT("Portanto, não os temais; porque nada há encoberto que não haja de ser descoberto, nem oculto que não haja de ser conhecido.");
    b->dados[MATEUS].capitulos[10].versos[27] = wxT("O que vos digo às escuras, dizei-o às claras; e o que escutais ao ouvido, dos eirados pregai-o.");
    b->dados[MATEUS].capitulos[10].versos[28] = wxT("E não temais os que matam o corpo, e não podem matar a alma; temei antes aquele que pode fazer perecer no inferno tanto a alma como o corpo.");
    b->dados[MATEUS].capitulos[10].versos[29] = wxT("Não se vendem dois passarinhos por um asse? e nenhum deles cairá em terra sem a vontade de vosso Pai.");
    b->dados[MATEUS].capitulos[10].versos[30] = wxT("E até mesmo os cabelos da vossa cabeça estão todos contados.");
    b->dados[MATEUS].capitulos[10].versos[31] = wxT("Não temais, pois; mais valeis vós do que muitos passarinhos.");
    b->dados[MATEUS].capitulos[10].versos[32] = wxT("Portanto, todo aquele que me confessar diante dos homens, também eu o confessarei diante de meu Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[10].versos[33] = wxT("Mas qualquer que me negar diante dos homens, também eu o negarei diante de meu Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[10].versos[34] = wxT("Não penseis que vim trazer paz à terra; não vim trazer paz, mas espada.");
    b->dados[MATEUS].capitulos[10].versos[35] = wxT("Porque eu vim pôr em dissensão o homem contra seu pai, a filha contra sua mãe, e a nora contra sua sogra;");
    b->dados[MATEUS].capitulos[10].versos[36] = wxT("e assim os inimigos do homem serão os da sua própria casa.");
    b->dados[MATEUS].capitulos[10].versos[37] = wxT("Quem ama o pai ou a mãe mais do que a mim não é digno de mim; e quem ama o filho ou a filha mais do que a mim não é digno de mim.");
    b->dados[MATEUS].capitulos[10].versos[38] = wxT("E quem não toma a sua cruz, e não segue após mim, não é digno de mim.");
    b->dados[MATEUS].capitulos[10].versos[39] = wxT("Quem achar a sua vida perdê-la-á, e quem perder a sua vida por amor de mim achá-la-á.");
    b->dados[MATEUS].capitulos[10].versos[40] = wxT("Quem vos recebe, a mim me recebe; e quem me recebe a mim, recebe aquele que me enviou.");
    b->dados[MATEUS].capitulos[10].versos[41] = wxT("Quem recebe um profeta na qualidade de profeta, receberá a recompensa de profeta; e quem recebe um justo na qualidade de justo, receberá a recompensa de justo.");
    b->dados[MATEUS].capitulos[10].versos[42] = wxT("E aquele que der até mesmo um copo de água fresca a um destes pequeninos, na qualidade de discípulo, em verdade vos digo que de modo algum perderá a sua recompensa.");

    b->dados[MATEUS].capitulos[11].versos[1] = wxT("Tendo acabado Jesus de dar instruções aos seus doze discípulos, partiu dali a ensinar e a pregar nas cidades da região.");
    b->dados[MATEUS].capitulos[11].versos[2] = wxT("Ora, quando João no cárcere ouviu falar das obras do Cristo, mandou pelos seus discípulos perguntar-lhe:");
    b->dados[MATEUS].capitulos[11].versos[3] = wxT("És tu aquele que havia de vir, ou havemos de esperar outro?");
    b->dados[MATEUS].capitulos[11].versos[4] = wxT("Respondeu-lhes Jesus: Ide contar a João as coisas que ouvis e vedes:");
    b->dados[MATEUS].capitulos[11].versos[5] = wxT("os cegos vêem, e os coxos andam; os leprosos são purificados, e os surdos ouvem; os mortos são ressuscitados, e aos pobres é anunciado o evangelho.");
    b->dados[MATEUS].capitulos[11].versos[6] = wxT("E bem-aventurado é aquele que não se escandalizar de mim.");
    b->dados[MATEUS].capitulos[11].versos[7] = wxT("Ao partirem eles, começou Jesus a dizer às multidões a respeito de João: que saístes a ver no deserto? um caniço agitado pelo vento?");
    b->dados[MATEUS].capitulos[11].versos[8] = wxT("Mas que saístes a ver? um homem trajado de vestes luxuosas? Eis que aqueles que trajam vestes luxuosas estão nas casas dos reis.");
    b->dados[MATEUS].capitulos[11].versos[9] = wxT("Mas por que saístes? para ver um profeta? Sim, vos digo, e muito mais do que profeta.");
    b->dados[MATEUS].capitulos[11].versos[10] = wxT("Este é aquele de quem está escrito: Eis aí envio eu ante a tua face o meu mensageiro, que há de preparar adiante de ti o teu caminho.");
    b->dados[MATEUS].capitulos[11].versos[11] = wxT("Em verdade vos digo que, entre os nascidos de mulher, não surgiu outro maior do que João, o Batista; mas aquele que é o menor no reino dos céus é maior do que ele.");
    b->dados[MATEUS].capitulos[11].versos[12] = wxT("E desde os dias de João, o Batista, até agora, o reino dos céus é tomado a força, e os violentos o tomam de assalto.");
    b->dados[MATEUS].capitulos[11].versos[13] = wxT("Pois todos os profetas e a lei profetizaram até João.");
    b->dados[MATEUS].capitulos[11].versos[14] = wxT("E, se quereis dar crédito, é este o Elias que havia de vir.");
    b->dados[MATEUS].capitulos[11].versos[15] = wxT("Quem tem ouvidos, ouça.");
    b->dados[MATEUS].capitulos[11].versos[16] = wxT("Mas, a quem compararei esta geração? É semelhante aos meninos que, sentados nas praças, clamam aos seus companheiros:");
    b->dados[MATEUS].capitulos[11].versos[17] = wxT("Tocamo-vos flauta, e não dançastes; cantamos lamentações, e não pranteastes.");
    b->dados[MATEUS].capitulos[11].versos[18] = wxT("Porquanto veio João, não comendo nem bebendo, e dizem: Tem demônio.");
    b->dados[MATEUS].capitulos[11].versos[19] = wxT("Veio o Filho do homem, comendo e bebendo, e dizem: Eis aí um comilão e bebedor de vinho, amigo de publicanos e pecadores. Entretanto a sabedoria é justificada pelas suas obras.");
    b->dados[MATEUS].capitulos[11].versos[20] = wxT("Então começou ele a lançar em rosto às cidades onde se operara a maior parte dos seus milagres, o não se haverem arrependido, dizendo:");
    b->dados[MATEUS].capitulos[11].versos[21] = wxT("Ai de ti, Corazin! ai de ti, Betsaida! porque, se em Tiro e em Sidom, se tivessem operado os milagres que em vós se operaram, há muito elas se teriam arrependido em cilício e em cinza.");
    b->dados[MATEUS].capitulos[11].versos[22] = wxT("Contudo, eu vos digo que para Tiro e Sidom haverá menos rigor, no dia do juízo, do que para vós.");
    b->dados[MATEUS].capitulos[11].versos[23] = wxT("E tu, Cafarnaum, porventura serás elevada até o céu? até o inferno descerás; porque, se em Sodoma se tivessem operado os milagres que em ti se operaram, teria ela permanecido até hoje.");
    b->dados[MATEUS].capitulos[11].versos[24] = wxT("Contudo, eu vos digo que no dia do juízo haverá menos rigor para a terra de Sodoma do que para ti.");
    b->dados[MATEUS].capitulos[11].versos[25] = wxT("Naquele tempo falou Jesus, dizendo: Graças te dou, ó Pai, Senhor do céu e da terra, porque ocultaste estas coisas aos sábios e entendidos, e as revelaste aos pequeninos.");
    b->dados[MATEUS].capitulos[11].versos[26] = wxT("Sim, ó Pai, porque assim foi do teu agrado.");
    b->dados[MATEUS].capitulos[11].versos[27] = wxT("Todas as coisas me foram entregues por meu Pai; e ninguém conhece plenamente o Filho, senão o Pai; e ninguém conhece plenamente o Pai, senão o Filho, e aquele a quem o Filho o quiser revelar.");
    b->dados[MATEUS].capitulos[11].versos[28] = wxT("Vinde a mim, todos os que estai cansados e oprimidos, e eu vos aliviarei.");
    b->dados[MATEUS].capitulos[11].versos[29] = wxT("Tomai sobre vós o meu jugo, e aprendei de mim, que sou manso e humilde de coração; e achareis descanso para as vossas almas.");
    b->dados[MATEUS].capitulos[11].versos[30] = wxT("Porque o meu jugo é suave, e o meu fardo e leve.");

    b->dados[MATEUS].capitulos[12].versos[1] = wxT("Naquele tempo passou Jesus pelas searas num dia de sábado; e os seus discípulos, sentindo fome, começaram a colher espigas, e a comer.");
    b->dados[MATEUS].capitulos[12].versos[2] = wxT("Os fariseus, vendo isso, disseram-lhe: Eis que os teus discípulos estão fazendo o que não é lícito fazer no sábado.");
    b->dados[MATEUS].capitulos[12].versos[3] = wxT("Ele, porém, lhes disse: Acaso não lestes o que fez Davi, quando teve fome, ele e seus companheiros?");
    b->dados[MATEUS].capitulos[12].versos[4] = wxT("Como entrou na casa de Deus, e como eles comeram os pães da proposição, que não lhe era lícito comer, nem a seus companheiros, mas somente aos sacerdotes?");
    b->dados[MATEUS].capitulos[12].versos[5] = wxT("Ou não lestes na lei que, aos sábados, os sacerdotes no templo violam o sábado, e ficam sem culpa?");
    b->dados[MATEUS].capitulos[12].versos[6] = wxT("Digo-vos, porém, que aqui está o que é maior do que o templo.");
    b->dados[MATEUS].capitulos[12].versos[7] = wxT("Mas, se vós soubésseis o que significa: Misericórdia quero, e não sacrifícios, não condenaríeis os inocentes.");
    b->dados[MATEUS].capitulos[12].versos[8] = wxT("Porque o Filho do homem até do sábado é o Senhor.");
    b->dados[MATEUS].capitulos[12].versos[9] = wxT("Partindo dali, entrou Jesus na sinagoga deles.");
    b->dados[MATEUS].capitulos[12].versos[10] = wxT("E eis que estava ali um homem que tinha uma das mãos atrofiadas; e eles, para poderem acusar a Jesus, o interrogaram, dizendo: É lícito curar nos sábados?");
    b->dados[MATEUS].capitulos[12].versos[11] = wxT("E ele lhes disse: Qual dentre vós será o homem que, tendo uma só ovelha, se num sábado ela cair numa cova, não há de lançar mão dela, e tirá-la?");
    b->dados[MATEUS].capitulos[12].versos[12] = wxT("Ora, quanto mais vale um homem do que uma ovelha! Portanto, é lícito fazer bem nos sábados.");
    b->dados[MATEUS].capitulos[12].versos[13] = wxT("Então disse àquele homem: estende a tua mão. E ele a estendeu, e lhe foi restituída sã como a outra.");
    b->dados[MATEUS].capitulos[12].versos[14] = wxT("Os fariseus, porém, saindo dali, tomaram conselho contra ele, para o matarem.");
    b->dados[MATEUS].capitulos[12].versos[15] = wxT("Jesus, percebendo isso, retirou-se dali. Acompanharam-no muitos; e ele curou a todos,");
    b->dados[MATEUS].capitulos[12].versos[16] = wxT("e advertiu-lhes que não o dessem a conhecer;");
    b->dados[MATEUS].capitulos[12].versos[17] = wxT("para que se cumprisse o que foi dito pelo profeta Isaías:");
    b->dados[MATEUS].capitulos[12].versos[18] = wxT("Eis aqui o meu servo que escolhi, o meu amado em quem a minha alma se compraz; porei sobre ele o meu espírito, e ele anunciará aos gentios o juízo.");
    b->dados[MATEUS].capitulos[12].versos[19] = wxT("Não contenderá, nem clamará, nem se ouvirá pelas ruas a sua voz.");
    b->dados[MATEUS].capitulos[12].versos[20] = wxT("Não esmagará a cana quebrada, e não apagará o morrão que fumega, até que faça triunfar o juízo;");
    b->dados[MATEUS].capitulos[12].versos[21] = wxT("e no seu nome os gentios esperarão.");
    b->dados[MATEUS].capitulos[12].versos[22] = wxT("Trouxeram-lhe então um endemoninhado cego e mudo; e ele o curou, de modo que o mudo falava e via.");
    b->dados[MATEUS].capitulos[12].versos[23] = wxT("E toda a multidão, maravilhada, dizia: É este, porventura, o Filho de Davi?");
    b->dados[MATEUS].capitulos[12].versos[24] = wxT("Mas os fariseus, ouvindo isto, disseram: Este não expulsa os demônios senão por Belzebu, príncipe dos demônios.");
    b->dados[MATEUS].capitulos[12].versos[25] = wxT("Jesus, porém, conhecendo-lhes os pensamentos, disse-lhes: Todo reino dividido contra si mesmo é devastado; e toda cidade, ou casa, dividida contra si mesma não subsistirá.");
    b->dados[MATEUS].capitulos[12].versos[26] = wxT("Ora, se Satanás expulsa a Satanás, está dividido contra si mesmo; como subsistirá, pois, o seus reino?");
    b->dados[MATEUS].capitulos[12].versos[27] = wxT("E, se eu expulso os demônios por Belzebu, por quem os expulsam os vossos filhos? Por isso, eles mesmos serão os vossos juízes.");
    b->dados[MATEUS].capitulos[12].versos[28] = wxT("Mas, se é pelo Espírito de Deus que eu expulso os demônios, logo é chegado a vós o reino de Deus.");
    b->dados[MATEUS].capitulos[12].versos[29] = wxT("Ou, como pode alguém entrar na casa do valente, e roubar-lhe os bens, se primeiro não amarrar o valente? e então lhe saquear a casa.");
    b->dados[MATEUS].capitulos[12].versos[30] = wxT("Quem não é comigo é contra mim; e quem comigo não ajunta, espalha.");
    b->dados[MATEUS].capitulos[12].versos[31] = wxT("Portanto vos digo: Todo pecado e blasfêmia se perdoará aos homens; mas a blasfêmia contra o Espírito não será perdoada.");
    b->dados[MATEUS].capitulos[12].versos[32] = wxT("Se alguém disser alguma palavra contra o Filho do homem, isso lhe será perdoado; mas se alguém falar contra o Espírito Santo, não lhe será perdoado, nem neste mundo, nem no vindouro.");
    b->dados[MATEUS].capitulos[12].versos[33] = wxT("Ou fazei a árvore boa, e o seu fruto bom; ou fazei a árvore má, e o seu fruto mau; porque pelo fruto se conhece a árvore.");
    b->dados[MATEUS].capitulos[12].versos[34] = wxT("Raça de víboras! como podeis vós falar coisas boas, sendo maus? pois do que há em abundância no coração, disso fala a boca.");
    b->dados[MATEUS].capitulos[12].versos[35] = wxT("O homem bom, do seu bom tesouro tira coisas boas, e o homem mau do mau tesouro tira coisas más.");
    b->dados[MATEUS].capitulos[12].versos[36] = wxT("Digo-vos, pois, que de toda palavra fútil que os homens disserem, hão de dar conta no dia do juízo.");
    b->dados[MATEUS].capitulos[12].versos[37] = wxT("Porque pelas tuas palavras serás justificado, e pelas tuas palavras serás condenado.");
    b->dados[MATEUS].capitulos[12].versos[38] = wxT("Então alguns dos escribas e dos fariseus, tomando a palavra, disseram: Mestre, queremos ver da tua parte algum sinal.");
    b->dados[MATEUS].capitulos[12].versos[39] = wxT("Mas ele lhes respondeu: Uma geração má e adúltera pede um sinal; e nenhum sinal se lhe dará, senão o do profeta Jonas;");
    b->dados[MATEUS].capitulos[12].versos[40] = wxT("pois, como Jonas esteve três dias e três noites no ventre do grande peixe, assim estará o Filho do homem três dias e três noites no seio da terra.");
    b->dados[MATEUS].capitulos[12].versos[41] = wxT("Os ninivitas se levantarão no juízo com esta geração, e a condenarão; porque se arrependeram com a pregação de Jonas. E eis aqui quem é maior do que Jonas.");
    b->dados[MATEUS].capitulos[12].versos[42] = wxT("A rainha do sul se levantará no juízo com esta geração, e a condenará; porque veio dos confins da terra para ouvir a sabedoria de Salomão. E eis aqui quem é maior do que Salomão.");
    b->dados[MATEUS].capitulos[12].versos[43] = wxT("Ora, havendo o espírito imundo saído do homem, anda por lugares áridos, buscando repouso, e não o encontra.");
    b->dados[MATEUS].capitulos[12].versos[44] = wxT("Então diz: Voltarei para minha casa, donde saí. E, chegando, acha-a desocupada, varrida e adornada.");
    b->dados[MATEUS].capitulos[12].versos[45] = wxT("Então vai e leva consigo outros sete espíritos piores do que ele e, entretanto, habitam ali; e o último estado desse homem vem a ser pior do que o primeiro. Assim há de acontecer também a esta geração perversa.");
    b->dados[MATEUS].capitulos[12].versos[46] = wxT("Enquanto ele ainda falava às multidões, estavam do lado de fora sua mãe e seus irmãos, procurando falar-lhe.");
    b->dados[MATEUS].capitulos[12].versos[47] = wxT("Disse-lhe alguém: Eis que estão ali fora tua mãe e teus irmãos, e procuram falar contigo.");
    b->dados[MATEUS].capitulos[12].versos[48] = wxT("Ele, porém, respondeu ao que lhe falava: Quem é minha mãe? e quem são meus irmãos?");
    b->dados[MATEUS].capitulos[12].versos[49] = wxT("E, estendendo a mão para os seus discípulos disse: Eis aqui minha mãe e meus irmãos.");
    b->dados[MATEUS].capitulos[12].versos[50] = wxT("Pois qualquer que fizer a vontade de meu Pai que está nos céus, esse é meu irmão, irmã e mãe.");

    b->dados[MATEUS].capitulos[13].versos[1] = wxT("No mesmo dia, tendo Jesus saído de casa, sentou-se à beira do mar;");
    b->dados[MATEUS].capitulos[13].versos[2] = wxT("e reuniram-se a ele grandes multidões, de modo que entrou num barco, e se sentou; e todo o povo estava em pé na praia.");
    b->dados[MATEUS].capitulos[13].versos[3] = wxT("E falou-lhes muitas coisas por parábolas, dizendo: Eis que o semeador saiu a semear.");
    b->dados[MATEUS].capitulos[13].versos[4] = wxT("e quando semeava, uma parte da semente caiu à beira do caminho, e vieram as aves e comeram.");
    b->dados[MATEUS].capitulos[13].versos[5] = wxT("E outra parte caiu em lugares pedregosos, onde não havia muita terra: e logo nasceu, porque não tinha terra profunda;");
    b->dados[MATEUS].capitulos[13].versos[6] = wxT("mas, saindo o sol, queimou-se e, por não ter raiz, secou-se.");
    b->dados[MATEUS].capitulos[13].versos[7] = wxT("E outra caiu entre espinhos; e os espinhos cresceram e a sufocaram.");
    b->dados[MATEUS].capitulos[13].versos[8] = wxT("Mas outra caiu em boa terra, e dava fruto, um a cem, outro a sessenta e outro a trinta por um.");
    b->dados[MATEUS].capitulos[13].versos[9] = wxT("Quem tem ouvidos, ouça.");
    b->dados[MATEUS].capitulos[13].versos[10] = wxT("E chegando-se a ele os discípulos, perguntaram-lhe: Por que lhes falas por parábolas?");
    b->dados[MATEUS].capitulos[13].versos[11] = wxT("Respondeu-lhes Jesus: Porque a vós é dado conhecer os mistérios do reino dos céus, mas a eles não lhes é dado;");
    b->dados[MATEUS].capitulos[13].versos[12] = wxT("pois ao que tem, dar-se-lhe-á, e terá em abundância; mas ao que não tem, até aquilo que tem lhe será tirado.");
    b->dados[MATEUS].capitulos[13].versos[13] = wxT("Por isso lhes falo por parábolas; porque eles, vendo, não vêem; e ouvindo, não ouvem nem entendem.");
    b->dados[MATEUS].capitulos[13].versos[14] = wxT("E neles se cumpre a profecia de Isaías, que diz: Ouvindo, ouvireis, e de maneira alguma entendereis; e, vendo, vereis, e de maneira alguma percebereis.");
    b->dados[MATEUS].capitulos[13].versos[15] = wxT("Porque o coração deste povo se endureceu, e com os ouvidos ouviram tardiamente, e fecharam os olhos, para que não vejam com os olhos, nem ouçam com os ouvidos, nem entendam com o coração, nem se convertam, e eu os cure.");
    b->dados[MATEUS].capitulos[13].versos[16] = wxT("Mas bem-aventurados os vossos olhos, porque vêem, e os vossos ouvidos, porque ouvem.");
    b->dados[MATEUS].capitulos[13].versos[17] = wxT("Pois, em verdade vos digo que muitos profetas e justos desejaram ver o que vedes, e não o viram; e ouvir o que ouvis, e não o ouviram.");
    b->dados[MATEUS].capitulos[13].versos[18] = wxT("Ouvi, pois, vós a parábola do semeador.");
    b->dados[MATEUS].capitulos[13].versos[19] = wxT("A todo o que ouve a palavra do reino e não a entende, vem o Maligno e arrebata o que lhe foi semeado no coração; este é o que foi semeado à beira do caminho.");
    b->dados[MATEUS].capitulos[13].versos[20] = wxT("E o que foi semeado nos lugares pedregosos, este é o que ouve a palavra, e logo a recebe com alegria;");
    b->dados[MATEUS].capitulos[13].versos[21] = wxT("mas não tem raiz em si mesmo, antes é de pouca duração; e sobrevindo a angústia e a perseguição por causa da palavra, logo se escandaliza.");
    b->dados[MATEUS].capitulos[13].versos[22] = wxT("E o que foi semeado entre os espinhos, este é o que ouve a palavra; mas os cuidados deste mundo e a sedução das riquezas sufocam a palavra, e ela fica infrutífera.");
    b->dados[MATEUS].capitulos[13].versos[23] = wxT("Mas o que foi semeado em boa terra, este é o que ouve a palavra, e a entende; e dá fruto, e um produz cem, outro sessenta, e outro trinta.");
    b->dados[MATEUS].capitulos[13].versos[24] = wxT("Propôs-lhes outra parábola, dizendo: O reino dos céus é semelhante ao homem que semeou boa semente no seu campo;");
    b->dados[MATEUS].capitulos[13].versos[25] = wxT("mas, enquanto os homens dormiam, veio o inimigo dele, semeou joio no meio do trigo, e retirou-se.");
    b->dados[MATEUS].capitulos[13].versos[26] = wxT("Quando, porém, a erva cresceu e começou a espigar, então apareceu também o joio.");
    b->dados[MATEUS].capitulos[13].versos[27] = wxT("Chegaram, pois, os servos do proprietário, e disseram-lhe: Senhor, não semeaste no teu campo boa semente? Donde, pois, vem o joio?");
    b->dados[MATEUS].capitulos[13].versos[28] = wxT("Respondeu-lhes: Algum inimigo é quem fez isso. E os servos lhe disseram: Queres, pois, que vamos arrancá-lo?");
    b->dados[MATEUS].capitulos[13].versos[29] = wxT("Ele, porém, disse: Não; para que, ao colher o joio, não arranqueis com ele também o trigo.");
    b->dados[MATEUS].capitulos[13].versos[30] = wxT("Deixai crescer ambos juntos até a ceifa; e, por ocasião da ceifa, direi aos ceifeiros: Ajuntai primeiro o joio, e atai-o em molhos para o queimar; o trigo, porém, recolhei-o no meu celeiro.");
    b->dados[MATEUS].capitulos[13].versos[31] = wxT("Propôs-lhes outra parábola, dizendo: O reino dos céus é semelhante a um grão de mostarda que um homem tomou, e semeou no seu campo;");
    b->dados[MATEUS].capitulos[13].versos[32] = wxT("o qual é realmente a menor de todas as sementes; mas, depois de ter crescido, é a maior das hortaliças, e faz-se árvore, de sorte que vêm as aves do céu, e se aninham nos seus ramos.");
    b->dados[MATEUS].capitulos[13].versos[33] = wxT("Outra parábola lhes disse: O reino dos céus é semelhante ao fermento que uma mulher tomou e misturou com três medidas de farinha, até ficar tudo levedado.");
    b->dados[MATEUS].capitulos[13].versos[34] = wxT("Todas estas coisas falou Jesus às multidões por parábolas, e sem parábolas nada lhes falava;");
    b->dados[MATEUS].capitulos[13].versos[35] = wxT("para que se cumprisse o que foi dito pelo profeta: Abrirei em parábolas a minha boca; publicarei coisas ocultas desde a fundação do mundo.");
    b->dados[MATEUS].capitulos[13].versos[36] = wxT("Então Jesus, deixando as multidões, entrou em casa. E chegaram-se a ele os seus discípulos, dizendo: Explica-nos a parábola do joio do campo.");
    b->dados[MATEUS].capitulos[13].versos[37] = wxT("E ele, respondendo, disse: O que semeia a boa semente é o Filho do homem;");
    b->dados[MATEUS].capitulos[13].versos[38] = wxT("o campo é o mundo; a boa semente são os filhos do reino; o joio são os filhos do maligno;");
    b->dados[MATEUS].capitulos[13].versos[39] = wxT("o inimigo que o semeou é o Diabo; a ceifa é o fim do mundo, e os celeiros são os anjos.");
    b->dados[MATEUS].capitulos[13].versos[40] = wxT("Pois assim como o joio é colhido e queimado no fogo, assim será no fim do mundo.");
    b->dados[MATEUS].capitulos[13].versos[41] = wxT("Mandará o Filho do homem os seus anjos, e eles ajuntarão do seu reino todos os que servem de tropeço, e os que praticam a iniqüidade,");
    b->dados[MATEUS].capitulos[13].versos[42] = wxT("e lançá-los-ão na fornalha de fogo; ali haverá choro e ranger de dentes.");
    b->dados[MATEUS].capitulos[13].versos[43] = wxT("Então os justos resplandecerão como o sol, no reino de seu Pai. Quem tem ouvidos, ouça.");
    b->dados[MATEUS].capitulos[13].versos[44] = wxT("O reino dos céus é semelhante a um tesouro escondido no campo, que um homem, ao descobri-lo, esconde; então, movido de gozo, vai, vende tudo quanto tem, e compra aquele campo.");
    b->dados[MATEUS].capitulos[13].versos[45] = wxT("Outrossim, o reino dos céus é semelhante a um negociante que buscava boas pérolas;");
    b->dados[MATEUS].capitulos[13].versos[46] = wxT("e encontrando uma pérola de grande valor, foi, vendeu tudo quanto tinha, e a comprou.");
    b->dados[MATEUS].capitulos[13].versos[47] = wxT("Igualmente, o reino dos céus é semelhante a uma rede lançada ao mar, e que apanhou toda espécie de peixes.");
    b->dados[MATEUS].capitulos[13].versos[48] = wxT("E, quando cheia, puxaram-na para a praia; e, sentando-se, puseram os bons em cestos; os ruins, porém, lançaram fora.");
    b->dados[MATEUS].capitulos[13].versos[49] = wxT("Assim será no fim do mundo: sairão os anjos, e separarão os maus dentre os justos,");
    b->dados[MATEUS].capitulos[13].versos[50] = wxT("e lançá-los-ão na fornalha de fogo; ali haverá choro e ranger de dentes.");
    b->dados[MATEUS].capitulos[13].versos[51] = wxT("Entendestes todas estas coisas? Disseram-lhe eles: Entendemos.");
    b->dados[MATEUS].capitulos[13].versos[52] = wxT("E disse-lhes: Por isso, todo escriba que se fez discípulo do reino dos céus é semelhante a um homem, proprietário, que tira do seu tesouro coisas novas e velhas.");
    b->dados[MATEUS].capitulos[13].versos[53] = wxT("E Jesus, tendo concluído estas parábolas, se retirou dali.");
    b->dados[MATEUS].capitulos[13].versos[54] = wxT("E, chegando à sua terra, ensinava o povo na sinagoga, de modo que este se maravilhava e dizia: Donde lhe vem esta sabedoria, e estes poderes milagrosos?");
    b->dados[MATEUS].capitulos[13].versos[55] = wxT("Não é este o filho do carpinteiro? e não se chama sua mãe Maria, e seus irmãos Tiago, José, Simão, e Judas?");
    b->dados[MATEUS].capitulos[13].versos[56] = wxT("E não estão entre nós todas as suas irmãs? Donde lhe vem, pois, tudo isto?");
    b->dados[MATEUS].capitulos[13].versos[57] = wxT("E escandalizavam-se dele. Jesus, porém, lhes disse: Um profeta não fica sem honra senão na sua terra e na sua própria casa.");
    b->dados[MATEUS].capitulos[13].versos[58] = wxT("E não fez ali muitos milagres, por causa da incredulidade deles.");

    b->dados[MATEUS].capitulos[14].versos[1] = wxT("Naquele tempo Herodes, o tetrarca, ouviu a fama de Jesus,");
    b->dados[MATEUS].capitulos[14].versos[2] = wxT("e disse aos seus cortesãos: Este é João, o Batista; ele ressuscitou dentre os mortos, e por isso estes poderes milagrosos operam nele.");
    b->dados[MATEUS].capitulos[14].versos[3] = wxT("Pois Herodes havia prendido a João, e, maniatando-o, o guardara no cárcere, por causa de Herodias, mulher de seu irmão Felipe;");
    b->dados[MATEUS].capitulos[14].versos[4] = wxT("porque João lhe dizia: Não te é lícito possuí-la.");
    b->dados[MATEUS].capitulos[14].versos[5] = wxT("E queria matá-lo, mas temia o povo; porque o tinham como profeta.");
    b->dados[MATEUS].capitulos[14].versos[6] = wxT("Festejando-se, porém, o dia natalício de Herodes, a filha de Herodias dançou no meio dos convivas, e agradou a Herodes,");
    b->dados[MATEUS].capitulos[14].versos[7] = wxT("pelo que este prometeu com juramento dar-lhe tudo o que pedisse.");
    b->dados[MATEUS].capitulos[14].versos[8] = wxT("E instigada por sua mãe, disse ela: Dá-me aqui num prato a cabeça de João, o Batista.");
    b->dados[MATEUS].capitulos[14].versos[9] = wxT("Entristeceu-se, então, o rei; mas, por causa do juramento, e dos que estavam à mesa com ele, ordenou que se lhe desse,");
    b->dados[MATEUS].capitulos[14].versos[10] = wxT("e mandou degolar a João no cárcere;");
    b->dados[MATEUS].capitulos[14].versos[11] = wxT("e a cabeça foi trazida num prato, e dada à jovem, e ela a levou para a sua mãe.");
    b->dados[MATEUS].capitulos[14].versos[12] = wxT("Então vieram os seus discípulos, levaram o corpo e o sepultaram; e foram anunciá-lo a Jesus.");
    b->dados[MATEUS].capitulos[14].versos[13] = wxT("Jesus, ouvindo isto, retirou-se dali num barco, para um, lugar deserto, à parte; e quando as multidões o souberam, seguiram-no a pé desde as cidades.");
    b->dados[MATEUS].capitulos[14].versos[14] = wxT("E ele, ao desembarcar, viu uma grande multidão; e, compadecendo-se dela, curou os seus enfermos.");
    b->dados[MATEUS].capitulos[14].versos[15] = wxT("Chegada a tarde, aproximaram-se dele os discípulos, dizendo: O lugar é deserto, e a hora é já passada; despede as multidões, para que vão às aldeias, e comprem o que comer.");
    b->dados[MATEUS].capitulos[14].versos[16] = wxT("Jesus, porém, lhes disse: Não precisam ir embora; dai-lhes vós de comer.");
    b->dados[MATEUS].capitulos[14].versos[17] = wxT("Então eles lhe disseram: Não temos aqui senão cinco pães e dois peixes.");
    b->dados[MATEUS].capitulos[14].versos[18] = wxT("E ele disse: trazei-mos aqui.");
    b->dados[MATEUS].capitulos[14].versos[19] = wxT("Tendo mandado às multidões que se reclinassem sobre a relva, tomou os cinco pães e os dois peixes e, erguendo os olhos ao céu, os abençoou; e partindo os pães, deu-os aos discípulos, e os discípulos às multidões.");
    b->dados[MATEUS].capitulos[14].versos[20] = wxT("Todos comeram e se fartaram; e dos pedaços que sobejaram levantaram doze cestos cheios.");
    b->dados[MATEUS].capitulos[14].versos[21] = wxT("Ora, os que comeram foram cerca de cinco mil homens, além de mulheres e crianças.");
    b->dados[MATEUS].capitulos[14].versos[22] = wxT("Logo em seguida obrigou os seus discípulos a entrar no barco, e passar adiante dele para o outro lado, enquanto ele despedia as multidões.");
    b->dados[MATEUS].capitulos[14].versos[23] = wxT("Tendo-as despedido, subiu ao monte para orar à parte. Ao anoitecer, estava ali sozinho.");
    b->dados[MATEUS].capitulos[14].versos[24] = wxT("Entrementes, o barco já estava a muitos estádios da terra, açoitado pelas ondas; porque o vento era contrário.");
    b->dados[MATEUS].capitulos[14].versos[25] = wxT("À quarta vigília da noite, foi Jesus ter com eles, andando sobre o mar.");
    b->dados[MATEUS].capitulos[14].versos[26] = wxT("Os discípulos, porém, ao vê-lo andando sobre o mar, assustaram-se e disseram: É um fantasma. E gritaram de medo.");
    b->dados[MATEUS].capitulos[14].versos[27] = wxT("Jesus, porém, imediatamente lhes falou, dizendo: Tende ânimo; sou eu; não temais.");
    b->dados[MATEUS].capitulos[14].versos[28] = wxT("Respondeu-lhe Pedro: Senhor! se és tu, manda-me ir ter contigo sobre as águas.");
    b->dados[MATEUS].capitulos[14].versos[29] = wxT("Disse-lhe ele: Vem. Pedro, descendo do barco, e andando sobre as águas, foi ao encontro de Jesus.");
    b->dados[MATEUS].capitulos[14].versos[30] = wxT("Mas, sentindo o vento, teve medo; e, começando a submergir, clamou: Senhor, salva-me.");
    b->dados[MATEUS].capitulos[14].versos[31] = wxT("Imediatamente estendeu Jesus a mão, segurou-o, e disse-lhe: Homem de pouca fé, por que duvidaste?");
    b->dados[MATEUS].capitulos[14].versos[32] = wxT("E logo que subiram para o barco, o vento cessou.");
    b->dados[MATEUS].capitulos[14].versos[33] = wxT("Então os que estavam no barco adoraram-no, dizendo: Verdadeiramente tu és Filho de Deus.");
    b->dados[MATEUS].capitulos[14].versos[34] = wxT("Ora, terminada a travessia, chegaram à terra em Genezaré.");
    b->dados[MATEUS].capitulos[14].versos[35] = wxT("Quando os homens daquele lugar o reconheceram, mandaram por toda aquela circunvizinhança, e trouxeram-lhe todos os enfermos;");
    b->dados[MATEUS].capitulos[14].versos[36] = wxT("e rogaram-lhe que apenas os deixasse tocar a orla do seu manto; e todos os que a tocaram ficaram curados.");

    b->dados[MATEUS].capitulos[15].versos[1] = wxT("Então chegaram a Jesus uns fariseus e escribas vindos de Jerusalém, e lhe perguntaram:");
    b->dados[MATEUS].capitulos[15].versos[2] = wxT("Por que transgridem os teus discípulos a tradição dos anciãos? pois não lavam as mãos, quando comem.");
    b->dados[MATEUS].capitulos[15].versos[3] = wxT("Ele, porém, respondendo, disse-lhes: E vós, por que transgredis o mandamento de Deus por causa da vossa tradição?");
    b->dados[MATEUS].capitulos[15].versos[4] = wxT("Pois Deus ordenou: Honra a teu pai e a tua mãe; e, Quem maldisser a seu pai ou a sua mãe, certamente morrerá.");
    b->dados[MATEUS].capitulos[15].versos[5] = wxT("Mas vós dizeis: Qualquer que disser a seu pai ou a sua mãe: O que poderias aproveitar de mim é oferta ao Senhor; esse de modo algum terá de honrar a seu pai.");
    b->dados[MATEUS].capitulos[15].versos[6] = wxT("E assim por causa da vossa tradição invalidastes a palavra de Deus.");
    b->dados[MATEUS].capitulos[15].versos[7] = wxT("Hipócritas! bem profetizou Isaias a vosso respeito, dizendo:");
    b->dados[MATEUS].capitulos[15].versos[8] = wxT("Este povo honra-me com os lábios; o seu coração, porém, está longe de mim.");
    b->dados[MATEUS].capitulos[15].versos[9] = wxT("Mas em vão me adoram, ensinando doutrinas que são preceitos de homem.");
    b->dados[MATEUS].capitulos[15].versos[10] = wxT("E, clamando a si a multidão, disse-lhes: Ouvi, e entendei:");
    b->dados[MATEUS].capitulos[15].versos[11] = wxT("Não é o que entra pela boca que contamina o homem; mas o que sai da boca, isso é o que o contamina.");
    b->dados[MATEUS].capitulos[15].versos[12] = wxT("Então os discípulos, aproximando-se dele, perguntaram-lhe: Sabes que os fariseus, ouvindo essas palavras, se escandalizaram?");
    b->dados[MATEUS].capitulos[15].versos[13] = wxT("Respondeu-lhes ele: Toda planta que meu Pai celestial não plantou será arrancada.");
    b->dados[MATEUS].capitulos[15].versos[14] = wxT("Deixai-os; são guias cegos; ora, se um cego guiar outro cego, ambos cairão no barranco.");
    b->dados[MATEUS].capitulos[15].versos[15] = wxT("E Pedro, tomando a palavra, disse-lhe: Explica-nos essa parábola.");
    b->dados[MATEUS].capitulos[15].versos[16] = wxT("Respondeu Jesus: Estai vós também ainda sem entender?");
    b->dados[MATEUS].capitulos[15].versos[17] = wxT("Não compreendeis que tudo o que entra pela boca desce pelo ventre, e é lançado fora?");
    b->dados[MATEUS].capitulos[15].versos[18] = wxT("Mas o que sai da boca procede do coração; e é isso o que contamina o homem.");
    b->dados[MATEUS].capitulos[15].versos[19] = wxT("Porque do coração procedem os maus pensamentos, homicídios, adultérios, prostituição, furtos, falsos testemunhos e blasfêmias.");
    b->dados[MATEUS].capitulos[15].versos[20] = wxT("São estas as coisas que contaminam o homem; mas o comer sem lavar as mãos, isso não o contamina.");
    b->dados[MATEUS].capitulos[15].versos[21] = wxT("Ora, partindo Jesus dali, retirou-se para as regiões de Tiro e Sidom.");
    b->dados[MATEUS].capitulos[15].versos[22] = wxT("E eis que uma mulher cananéia, provinda daquelas cercania, clamava, dizendo: Senhor, Filho de Davi, tem compaixão de mim, que minha filha está horrivelmente endemoninhada.");
    b->dados[MATEUS].capitulos[15].versos[23] = wxT("Contudo ele não lhe respondeu palavra. Chegando-se, pois, a ele os seus discípulos, rogavam-lhe, dizendo: Despede-a, porque vem clamando atrás de nós.");
    b->dados[MATEUS].capitulos[15].versos[24] = wxT("Respondeu-lhes ele: Não fui enviado senão às ovelhas perdidas da casa de Israel.");
    b->dados[MATEUS].capitulos[15].versos[25] = wxT("Então veio ela e, adorando-o, disse: Senhor, socorre-me.");
    b->dados[MATEUS].capitulos[15].versos[26] = wxT("Ele, porém, respondeu: Não é bom tomar o pão dos filhos e lançá-lo aos cachorrinhos.");
    b->dados[MATEUS].capitulos[15].versos[27] = wxT("Ao que ela disse: Sim, Senhor, mas até os cachorrinhos comem das migalhas que caem da mesa dos seus donos.");
    b->dados[MATEUS].capitulos[15].versos[28] = wxT("Então respondeu Jesus, e disse-lhe: ó mulher, grande é a tua fé! seja-te feito como queres. E desde aquela hora sua filha ficou sã.");
    b->dados[MATEUS].capitulos[15].versos[29] = wxT("Partindo Jesus dali, chegou ao pé do mar da Galiléia; e, subindo ao monte, sentou-se ali.");
    b->dados[MATEUS].capitulos[15].versos[30] = wxT("E vieram a ele grandes multidões, trazendo consigo coxos, aleijados, cegos, mudos, e outros muitos, e lhos puseram aos pés; e ele os curou;");
    b->dados[MATEUS].capitulos[15].versos[31] = wxT("de modo que a multidão se admirou, vendo mudos a falar, aleijados a ficar sãos, coxos a andar, cegos a ver; e glorificaram ao Deus de Israel.");
    b->dados[MATEUS].capitulos[15].versos[32] = wxT("Jesus chamou os seus discípulos, e disse: Tenho compaixão da multidão, porque já faz três dias que eles estão comigo, e não têm o que comer; e não quero despedi-los em jejum, para que não desfaleçam no caminho.");
    b->dados[MATEUS].capitulos[15].versos[33] = wxT("Disseram-lhe os discípulos: Donde nos viriam num deserto tantos pães, para fartar tamanha multidão?");
    b->dados[MATEUS].capitulos[15].versos[34] = wxT("Perguntou-lhes Jesus: Quantos pães tendes? E responderam: Sete, e alguns peixinhos.");
    b->dados[MATEUS].capitulos[15].versos[35] = wxT("E tendo ele ordenado ao povo que se sentasse no chão,");
    b->dados[MATEUS].capitulos[15].versos[36] = wxT("tomou os sete pães e os peixes, e havendo dado graças, partiu-os, e os entregava aos discípulos, e os discípulos á multidão.");
    b->dados[MATEUS].capitulos[15].versos[37] = wxT("Assim todos comeram, e se fartaram; e do que sobejou dos pedaços levantaram sete alcofas cheias.");
    b->dados[MATEUS].capitulos[15].versos[38] = wxT("Ora, os que tinham comido eram quatro mil homens além de mulheres e crianças.");
    b->dados[MATEUS].capitulos[15].versos[39] = wxT("E havendo Jesus despedido a multidão, entrou no barco, e foi para os confins de Magadã.");

    b->dados[MATEUS].capitulos[16].versos[1] = wxT("Então chegaram a ele os fariseus e os saduceus e, para o experimentarem, pediram-lhe que lhes mostrasse algum sinal do céu.");
    b->dados[MATEUS].capitulos[16].versos[2] = wxT("Mas ele respondeu, e disse-lhes: Ao cair da tarde, dizeis: Haverá bom tempo, porque o céu está rubro.");
    b->dados[MATEUS].capitulos[16].versos[3] = wxT("E pela manhã: Hoje haverá tempestade, porque o céu está de um vermelho sombrio. Ora, sabeis discernir o aspecto do céu, e não podeis discernir os sinais dos tempos?");
    b->dados[MATEUS].capitulos[16].versos[4] = wxT("Uma geração má e adúltera pede um sinal, e nenhum sinal lhe será dado, senão o de Jonas. E, deixando-os, retirou-se.");
    b->dados[MATEUS].capitulos[16].versos[5] = wxT("Quando os discípulos passaram para o outro lado, esqueceram-se de levar pão.");
    b->dados[MATEUS].capitulos[16].versos[6] = wxT("E Jesus lhes disse: Olhai, e acautelai-vos do fermento dos fariseus e dos saduceus.");
    b->dados[MATEUS].capitulos[16].versos[7] = wxT("Pelo que eles arrazoavam entre si, dizendo: É porque não trouxemos pão.");
    b->dados[MATEUS].capitulos[16].versos[8] = wxT("E Jesus, percebendo isso, disse: Por que arrazoais entre vós por não terdes pão, homens de pouca fé?");
    b->dados[MATEUS].capitulos[16].versos[9] = wxT("Não compreendeis ainda, nem vos lembrais dos cinco pães para os cinco mil, e de quantos cestos levantastes?");
    b->dados[MATEUS].capitulos[16].versos[10] = wxT("Nem dos sete pães para os quatro mil, e de quantas alcofas levantastes?");
    b->dados[MATEUS].capitulos[16].versos[11] = wxT("Como não compreendeis que não nos falei a respeito de pães? Mas guardai-vos do fermento dos fariseus e dos saduceus.");
    b->dados[MATEUS].capitulos[16].versos[12] = wxT("Então entenderam que não dissera que se guardassem, do fermento dos pães, mas da doutrina dos fariseus e dos saduceus.");
    b->dados[MATEUS].capitulos[16].versos[13] = wxT("Tendo Jesus chegado às regiões de Cesaréia de Felipe, interrogou os seus discípulos, dizendo: Quem dizem os homens ser o Filho do homem?");
    b->dados[MATEUS].capitulos[16].versos[14] = wxT("Responderam eles: Uns dizem que é João, o Batista; outros, Elias; outros, Jeremias, ou algum dos profetas.");
    b->dados[MATEUS].capitulos[16].versos[15] = wxT("Mas vós, perguntou-lhes Jesus, quem dizeis que eu sou?");
    b->dados[MATEUS].capitulos[16].versos[16] = wxT("Respondeu-lhe Simão Pedro: Tu és o Cristo, o Filho do Deus vivo.");
    b->dados[MATEUS].capitulos[16].versos[17] = wxT("Disse-lhe Jesus: Bem-aventurado és tu, Simão Barjonas, porque não foi carne e sangue que to revelou, mas meu Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[16].versos[18] = wxT("Pois também eu te digo que tu és Pedro, e sobre esta pedra edificarei a minha igreja, e as portas do inferno não prevalecerão contra ela;");
    b->dados[MATEUS].capitulos[16].versos[19] = wxT("dar-te-ei as chaves do reino dos céus; o que ligares, pois, na terra será ligado nos céus, e o que desligares na terra será desligado nos céus.");
    b->dados[MATEUS].capitulos[16].versos[20] = wxT("Então ordenou aos discípulos que a ninguém dissessem que ele era o Cristo.");
    b->dados[MATEUS].capitulos[16].versos[21] = wxT("Desde então começou Jesus Cristo a mostrar aos seus discípulos que era necessário que ele fosse a Jerusalém, que padecesse muitas coisas dos anciãos, dos principais sacerdotes, e dos escribas, que fosse morto, e que ao terceiro dia ressuscitasse.");
    b->dados[MATEUS].capitulos[16].versos[22] = wxT("E Pedro, tomando-o à parte, começou a repreendê-lo, dizendo: Tenha Deus compaixão de ti, Senhor; isso de modo nenhum te acontecerá.");
    b->dados[MATEUS].capitulos[16].versos[23] = wxT("Ele, porém, voltando-se, disse a Pedro: Para trás de mim, Satanás, que me serves de escândalo; porque não estás pensando nas coisas que são de Deus, mas sim nas que são dos homens.");
    b->dados[MATEUS].capitulos[16].versos[24] = wxT("Então disse Jesus aos seus discípulos: Se alguém quer vir após mim, negue-se a si mesmo, tome a sua cruz, e siga-me;");
    b->dados[MATEUS].capitulos[16].versos[25] = wxT("pois, quem quiser salvar a sua vida por amor de mim perdê-la-á; mas quem perder a sua vida por amor de mim, achá-la-á.");
    b->dados[MATEUS].capitulos[16].versos[26] = wxT("Pois que aproveita ao homem se ganhar o mundo inteiro e perder a sua vida? ou que dará o homem em troca da sua vida?");
    b->dados[MATEUS].capitulos[16].versos[27] = wxT("Porque o Filho do homem há de vir na glória de seu Pai, com os seus anjos; e então retribuirá a cada um segundo as suas obras.");
    b->dados[MATEUS].capitulos[16].versos[28] = wxT("Em verdade vos digo, alguns dos que aqui estão de modo nenhum provarão a morte até que vejam vir o Filho do homem no seu reino.");

    b->dados[MATEUS].capitulos[17].versos[1] = wxT("Seis dias depois, tomou Jesus consigo a Pedro, a Tiago e a João, irmão deste, e os conduziu à parte a um alto monte;");
    b->dados[MATEUS].capitulos[17].versos[2] = wxT("e foi transfigurado diante deles; o seu rosto resplandeceu como o sol, e as suas vestes tornaram-se brancas como a luz.");
    b->dados[MATEUS].capitulos[17].versos[3] = wxT("E eis que lhes apareceram Moisés e Elias, falando com ele.");
    b->dados[MATEUS].capitulos[17].versos[4] = wxT("Pedro, tomando a palavra, disse a Jesus: Senhor, bom é estarmos aqui; se queres, farei aqui três cabanas, uma para ti, outra para Moisés, e outra para Elias.");
    b->dados[MATEUS].capitulos[17].versos[5] = wxT("Estando ele ainda a falar, eis que uma nuvem luminosa os cobriu; e dela saiu uma voz que dizia: Este é o meu Filho amado, em quem me comprazo; a ele ouvi.");
    b->dados[MATEUS].capitulos[17].versos[6] = wxT("Os discípulos, ouvindo isso, caíram com o rosto em terra, e ficaram grandemente atemorizados.");
    b->dados[MATEUS].capitulos[17].versos[7] = wxT("Chegou-se, pois, Jesus e, tocando-os, disse: Levantai-vos e não temais.");
    b->dados[MATEUS].capitulos[17].versos[8] = wxT("E, erguendo eles os olhos, não viram a ninguém senão a Jesus somente.");
    b->dados[MATEUS].capitulos[17].versos[9] = wxT("Enquanto desciam do monte, Jesus lhes ordenou: A ninguém conteis a visão, até que o Filho do homem seja levantado dentre os mortos.");
    b->dados[MATEUS].capitulos[17].versos[10] = wxT("Perguntaram-lhe os discípulos: Por que dizem então os escribas que é necessário que Elias venha primeiro?");
    b->dados[MATEUS].capitulos[17].versos[11] = wxT("Respondeu ele: Na verdade Elias havia de vir e restaurar todas as coisas;");
    b->dados[MATEUS].capitulos[17].versos[12] = wxT("digo-vos, porém, que Elias já veio, e não o reconheceram; mas fizeram-lhe tudo o que quiseram. Assim também o Filho do homem há de padecer às mãos deles.");
    b->dados[MATEUS].capitulos[17].versos[13] = wxT("Então entenderam os discípulos que lhes falava a respeito de João, o Batista.");
    b->dados[MATEUS].capitulos[17].versos[14] = wxT("Quando chegaram à multidão, aproximou-se de Jesus um homem que, ajoelhando-se diante dele, disse:");
    b->dados[MATEUS].capitulos[17].versos[15] = wxT("Senhor, tem compaixão de meu filho, porque é epiléptico e sofre muito; pois muitas vezes cai no fogo, e muitas vezes na água.");
    b->dados[MATEUS].capitulos[17].versos[16] = wxT("Eu o trouxe aos teus discípulos, e não o puderam curar.");
    b->dados[MATEUS].capitulos[17].versos[17] = wxT("E Jesus, respondendo, disse: ó geração incrédula e perversa! até quando estarei convosco? até quando vos sofrerei? Trazei-mo aqui.");
    b->dados[MATEUS].capitulos[17].versos[18] = wxT("Então Jesus repreendeu ao demônio, o qual saiu de menino, que desde aquela hora ficou curado.");
    b->dados[MATEUS].capitulos[17].versos[19] = wxT("Depois os discípulos, aproximando-se de Jesus em particular, perguntaram-lhe: Por que não pudemos nós expulsá-lo?");
    b->dados[MATEUS].capitulos[17].versos[20] = wxT("Disse-lhes ele: Por causa da vossa pouca fé; pois em verdade vos digo que, se tiverdes fé como um grão de mostarda direis a este monte: Passa daqui para acolá, e ele há de passar; e nada vos será impossível.");
    b->dados[MATEUS].capitulos[17].versos[21] = wxT("{mas esta casta de demônios não se expulsa senão à força de oração e de jejum.}");
    b->dados[MATEUS].capitulos[17].versos[22] = wxT("Ora, achando-se eles na Galiléia, disse-lhes Jesus: O Filho do homem está para ser entregue nas mãos dos homens;");
    b->dados[MATEUS].capitulos[17].versos[23] = wxT("e matá-lo-ão, e ao terceiro dia ressurgirá. E eles se entristeceram grandemente.");
    b->dados[MATEUS].capitulos[17].versos[24] = wxT("Tendo eles chegado a Cafarnaum, aproximaram-se de Pedro os que cobravam as didracmas, e lhe perguntaram: O vosso mestre não paga as didracmas?");
    b->dados[MATEUS].capitulos[17].versos[25] = wxT("Disse ele: Sim. Ao entrar Pedro em casa, Jesus se lhe antecipou, perguntando: Que te parece, Simão? De quem cobram os reis da terra imposto ou tributo? dos seus filhos, ou dos alheios?");
    b->dados[MATEUS].capitulos[17].versos[26] = wxT("Quando ele respondeu: Dos alheios, disse-lhe Jesus: Logo, são isentos os filhos.");
    b->dados[MATEUS].capitulos[17].versos[27] = wxT("Mas, para que não os escandalizemos, vai ao mar, lança o anzol, tira o primeiro peixe que subir e, abrindo-lhe a boca, encontrarás um estáter; toma-o, e dá-lho por mim e por ti.");

    b->dados[MATEUS].capitulos[18].versos[1] = wxT("Naquela hora chegaram-se a Jesus os discípulos e perguntaram: Quem é o maior no reino dos céus?");
    b->dados[MATEUS].capitulos[18].versos[2] = wxT("Jesus, chamando uma criança, colocou-a no meio deles,");
    b->dados[MATEUS].capitulos[18].versos[3] = wxT("e disse: Em verdade vos digo que se não vos converterdes e não vos fizerdes como crianças, de modo algum entrareis no reino dos céus.");
    b->dados[MATEUS].capitulos[18].versos[4] = wxT("Portanto, quem se tornar humilde como esta criança, esse é o maior no reino dos céus.");
    b->dados[MATEUS].capitulos[18].versos[5] = wxT("E qualquer que receber em meu nome uma criança tal como esta, a mim me recebe.");
    b->dados[MATEUS].capitulos[18].versos[6] = wxT("Mas qualquer que fizer tropeçar um destes pequeninos que crêem em mim, melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho, e se submergisse na profundeza do mar.");
    b->dados[MATEUS].capitulos[18].versos[7] = wxT("Ai do mundo, por causa dos tropeços! pois é inevitável que venham; mas ai do homem por quem o tropeço vier!");
    b->dados[MATEUS].capitulos[18].versos[8] = wxT("Se, pois, a tua mão ou o teu pé te fizer tropeçar, corta-o, lança-o de ti; melhor te é entrar na vida aleijado, ou coxo, do que, tendo duas mãos ou dois pés, ser lançado no fogo eterno.");
    b->dados[MATEUS].capitulos[18].versos[9] = wxT("E, se teu olho te fizer tropeçar, arranca-o, e lança-o de ti; melhor te é entrar na vida com um só olho, do que tendo dois olhos, ser lançado no inferno de fogo.");
    b->dados[MATEUS].capitulos[18].versos[10] = wxT("Vede, não desprezeis a nenhum destes pequeninos; pois eu vos digo que os seus anjos nos céus sempre vêm a face de meu Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[18].versos[11] = wxT("{Porque o Filho do homem veio salvar o que se havia perdido.}");
    b->dados[MATEUS].capitulos[18].versos[12] = wxT("Que vos parece? Se alguém tiver cem ovelhas, e uma delas se extraviar, não deixará as noventa e nove nos montes para ir buscar a que se extraviou?");
    b->dados[MATEUS].capitulos[18].versos[13] = wxT("E, se acontecer achá-la, em verdade vos digo que maior prazer tem por esta do que pelas noventa e nove que não se extraviaram.");
    b->dados[MATEUS].capitulos[18].versos[14] = wxT("Assim também não é da vontade de vosso Pai que está nos céus, que venha a perecer um só destes pequeninos.");
    b->dados[MATEUS].capitulos[18].versos[15] = wxT("Ora, se teu irmão pecar, vai, e repreende-o entre ti e ele só; se te ouvir, terás ganho teu irmão;");
    b->dados[MATEUS].capitulos[18].versos[16] = wxT("mas se não te ouvir, leva ainda contigo um ou dois, para que pela boca de duas ou três testemunhas toda palavra seja confirmada.");
    b->dados[MATEUS].capitulos[18].versos[17] = wxT("Se recusar ouvi-los, dize-o à igreja; e, se também recusar ouvir a igreja, considera-o como gentio e publicano.");
    b->dados[MATEUS].capitulos[18].versos[18] = wxT("Em verdade vos digo: Tudo quanto ligardes na terra será ligado no céu; e tudo quanto desligardes na terra será desligado no céu.");
    b->dados[MATEUS].capitulos[18].versos[19] = wxT("Ainda vos digo mais: Se dois de vós na terra concordarem acerca de qualquer coisa que pedirem, isso lhes será feito por meu Pai, que está nos céus.");
    b->dados[MATEUS].capitulos[18].versos[20] = wxT("Pois onde se acham dois ou três reunidos em meu nome, aí estou eu no meio deles.");
    b->dados[MATEUS].capitulos[18].versos[21] = wxT("Então Pedro, aproximando-se dele, lhe perguntou: Senhor, até quantas vezes pecará meu irmão contra mim, e eu hei de perdoar? Até sete?");
    b->dados[MATEUS].capitulos[18].versos[22] = wxT("Respondeu-lhe Jesus: Não te digo que até sete; mas até setenta vezes sete.");
    b->dados[MATEUS].capitulos[18].versos[23] = wxT("Por isso o reino dos céus é comparado a um rei que quis tomar contas a seus servos;");
    b->dados[MATEUS].capitulos[18].versos[24] = wxT("e, tendo começado a tomá-las, foi-lhe apresentado um que lhe devia dez mil talentos;");
    b->dados[MATEUS].capitulos[18].versos[25] = wxT("mas não tendo ele com que pagar, ordenou seu senhor que fossem vendidos, ele, sua mulher, seus filhos, e tudo o que tinha, e que se pagasse a dívida.");
    b->dados[MATEUS].capitulos[18].versos[26] = wxT("Então aquele servo, prostrando-se, o reverenciava, dizendo: Senhor, tem paciência comigo, que tudo te pagarei.");
    b->dados[MATEUS].capitulos[18].versos[27] = wxT("O senhor daquele servo, pois, movido de compaixão, soltou-o, e perdoou-lhe a dívida.");
    b->dados[MATEUS].capitulos[18].versos[28] = wxT("Saindo, porém, aquele servo, encontrou um dos seus conservos, que lhe devia cem denários; e, segurando-o, o sufocava, dizendo: Paga o que me deves.");
    b->dados[MATEUS].capitulos[18].versos[29] = wxT("Então o seu companheiro, caindo-lhe aos pés, rogava-lhe, dizendo: Tem paciência comigo, que te pagarei.");
    b->dados[MATEUS].capitulos[18].versos[30] = wxT("Ele, porém, não quis; antes foi encerrá-lo na prisão, até que pagasse a dívida.");
    b->dados[MATEUS].capitulos[18].versos[31] = wxT("Vendo, pois, os seus conservos o que acontecera, contristaram-se grandemente, e foram revelar tudo isso ao seu senhor.");
    b->dados[MATEUS].capitulos[18].versos[32] = wxT("Então o seu senhor, chamando-o á sua presença, disse-lhe: Servo malvado, perdoei-te toda aquela dívida, porque me suplicaste;");
    b->dados[MATEUS].capitulos[18].versos[33] = wxT("não devias tu também ter compaixão do teu companheiro, assim como eu tive compaixão de ti?");
    b->dados[MATEUS].capitulos[18].versos[34] = wxT("E, indignado, o seu senhor o entregou aos verdugos, até que pagasse tudo o que lhe devia.");
    b->dados[MATEUS].capitulos[18].versos[35] = wxT("Assim vos fará meu Pai celestial, se de coração não perdoardes, cada um a seu irmão.");

    b->dados[MATEUS].capitulos[19].versos[1] = wxT("Tendo Jesus concluído estas palavras, partiu da Galiléia, e foi para os confins da Judéia, além do Jordão;");
    b->dados[MATEUS].capitulos[19].versos[2] = wxT("e seguiram-no grandes multidões, e curou-os ali.");
    b->dados[MATEUS].capitulos[19].versos[3] = wxT("Aproximaram-se dele alguns fariseus que o experimentavam, dizendo: É lícito ao homem repudiar sua mulher por qualquer motivo?");
    b->dados[MATEUS].capitulos[19].versos[4] = wxT("Respondeu-lhe Jesus: Não tendes lido que o Criador os fez desde o princípio homem e mulher,");
    b->dados[MATEUS].capitulos[19].versos[5] = wxT("e que ordenou: Por isso deixará o homem pai e mãe, e unir-se-á a sua mulher; e serão os dois uma só carne?");
    b->dados[MATEUS].capitulos[19].versos[6] = wxT("Assim já não são mais dois, mas um só carne. Portanto o que Deus ajuntou, não o separe o homem.");
    b->dados[MATEUS].capitulos[19].versos[7] = wxT("Responderam-lhe: Então por que mandou Moisés dar-lhe carta de divórcio e repudiá-la?");
    b->dados[MATEUS].capitulos[19].versos[8] = wxT("Disse-lhes ele: Pela dureza de vossos corações Moisés vos permitiu repudiar vossas mulheres; mas não foi assim desde o princípio.");
    b->dados[MATEUS].capitulos[19].versos[9] = wxT("Eu vos digo porém, que qualquer que repudiar sua mulher, a não ser por causa de infidelidade, e casar com outra, comete adultério; {e o que casar com a repudiada também comete adultério.}");
    b->dados[MATEUS].capitulos[19].versos[10] = wxT("Disseram-lhe os discípulos: Se tal é a condição do homem relativamente à mulher, não convém casar.");
    b->dados[MATEUS].capitulos[19].versos[11] = wxT("Ele, porém, lhes disse: Nem todos podem aceitar esta palavra, mas somente aqueles a quem é dado.");
    b->dados[MATEUS].capitulos[19].versos[12] = wxT("Porque há eunucos que nasceram assim; e há eunucos que pelos homens foram feitos tais; e outros há que a si mesmos se fizeram eunucos por causa do reino dos céus. Quem pode aceitar isso, aceite-o.");
    b->dados[MATEUS].capitulos[19].versos[13] = wxT("Então lhe trouxeram algumas crianças para que lhes impusesse as mãos, e orasse; mas os discípulos os repreenderam.");
    b->dados[MATEUS].capitulos[19].versos[14] = wxT("Jesus, porém, disse: Deixai as crianças e não as impeçais de virem a mim, porque de tais é o reino dos céus.");
    b->dados[MATEUS].capitulos[19].versos[15] = wxT("E, depois de lhes impor as mãos, partiu dali.");
    b->dados[MATEUS].capitulos[19].versos[16] = wxT("E eis que se aproximou dele um jovem, e lhe disse: Mestre, que bem farei para conseguir a vida eterna?");
    b->dados[MATEUS].capitulos[19].versos[17] = wxT("Respondeu-lhe ele: Por que me perguntas sobre o que é bom? Um só é bom; mas se é que queres entrar na vida, guarda os mandamentos.");
    b->dados[MATEUS].capitulos[19].versos[18] = wxT("Perguntou-lhe ele: Quais? Respondeu Jesus: Não matarás; não adulterarás; não furtarás; não dirás falso testemunho;");
    b->dados[MATEUS].capitulos[19].versos[19] = wxT("honra a teu pai e a tua mãe; e amarás o teu próximo como a ti mesmo.");
    b->dados[MATEUS].capitulos[19].versos[20] = wxT("Disse-lhe o jovem: Tudo isso tenho guardado; que me falta ainda?");
    b->dados[MATEUS].capitulos[19].versos[21] = wxT("Disse-lhe Jesus: Se queres ser perfeito, vai, vende tudo o que tens e dá-o aos pobres, e terás um tesouro no céu; e vem, segue-me.");
    b->dados[MATEUS].capitulos[19].versos[22] = wxT("Mas o jovem, ouvindo essa palavra, retirou-se triste; porque possuía muitos bens.");
    b->dados[MATEUS].capitulos[19].versos[23] = wxT("Disse então Jesus aos seus discípulos: Em verdade vos digo que um rico dificilmente entrará no reino dos céus.");
    b->dados[MATEUS].capitulos[19].versos[24] = wxT("E outra vez vos digo que é mais fácil um camelo passar pelo fundo duma agulha, do que entrar um rico no reino de Deus.");
    b->dados[MATEUS].capitulos[19].versos[25] = wxT("Quando os seus discípulos ouviram isso, ficaram grandemente maravilhados, e perguntaram: Quem pode, então, ser salvo?");
    b->dados[MATEUS].capitulos[19].versos[26] = wxT("Jesus, fixando neles o olhar, respondeu: Aos homens é isso impossível, mas a Deus tudo é possível.");
    b->dados[MATEUS].capitulos[19].versos[27] = wxT("Então Pedro, tomando a palavra, disse-lhe: Eis que nós deixamos tudo, e te seguimos; que recompensa, pois, teremos nós?");
    b->dados[MATEUS].capitulos[19].versos[28] = wxT("Ao que lhe disse Jesus: Em verdade vos digo a vós que me seguistes, que na regeneração, quando o Filho do homem se assentar no trono da sua glória, sentar-vos-eis também vós sobre doze tronos, para julgar as doze tribos de Israel.");
    b->dados[MATEUS].capitulos[19].versos[29] = wxT("E todo o que tiver deixado casas, ou irmãos, ou irmãs, ou pai, ou mãe, ou filhos, ou terras, por amor do meu nome, receberá cem vezes tanto, e herdará a vida eterna.");
    b->dados[MATEUS].capitulos[19].versos[30] = wxT("Entretanto, muitos que são primeiros serão últimos; e muitos que são últimos serão primeiros.");

    b->dados[MATEUS].capitulos[20].versos[1] = wxT("Porque o reino dos céus é semelhante a um homem, proprietário, que saiu de madrugada a contratar trabalhadores para a sua vinha.");
    b->dados[MATEUS].capitulos[20].versos[2] = wxT("Ajustou com os trabalhadores o salário de um denário por dia, e mandou-os para a sua vinha.");
    b->dados[MATEUS].capitulos[20].versos[3] = wxT("Cerca da hora terceira saiu, e viu que estavam outros, ociosos, na praça,");
    b->dados[MATEUS].capitulos[20].versos[4] = wxT("e disse-lhes: Ide também vós para a vinha, e dar-vos-ei o que for justo. E eles foram.");
    b->dados[MATEUS].capitulos[20].versos[5] = wxT("Outra vez saiu, cerca da hora sexta e da nona, e fez o mesmo.");
    b->dados[MATEUS].capitulos[20].versos[6] = wxT("Responderam-lhe eles: Porque ninguém nos contratou. Disse-lhes ele: Ide também vós para a vinha.");
    b->dados[MATEUS].capitulos[20].versos[7] = wxT("Responderam-lhe eles: Porque ninguém nos contratou. Disse-lhes ele: Ide também vós para a vinha.");
    b->dados[MATEUS].capitulos[20].versos[8] = wxT("Ao anoitecer, disse o senhor da vinha ao seu mordomo: Chama os trabalhadores, e paga-lhes o salário, começando pelos últimos até os primeiros.");
    b->dados[MATEUS].capitulos[20].versos[9] = wxT("Chegando, pois, os que tinham ido cerca da hora undécima, receberam um denário cada um.");
    b->dados[MATEUS].capitulos[20].versos[10] = wxT("Vindo, então, os primeiros, pensaram que haviam de receber mais; mas do mesmo modo receberam um denário cada um.");
    b->dados[MATEUS].capitulos[20].versos[11] = wxT("E ao recebê-lo, murmuravam contra o proprietário, dizendo:");
    b->dados[MATEUS].capitulos[20].versos[12] = wxT("Estes últimos trabalharam somente uma hora, e os igualastes a nós, que suportamos a fadiga do dia inteiro e o forte calor.");
    b->dados[MATEUS].capitulos[20].versos[13] = wxT("Mas ele, respondendo, disse a um deles: Amigo, não te faço injustiça; não ajustaste comigo um denário?");
    b->dados[MATEUS].capitulos[20].versos[14] = wxT("Toma o que é teu, e vai-te; eu quero dar a este último tanto como a ti.");
    b->dados[MATEUS].capitulos[20].versos[15] = wxT("Não me é lícito fazer o que quero do que é meu? Ou é mau o teu olho porque eu sou bom?");
    b->dados[MATEUS].capitulos[20].versos[16] = wxT("Assim os últimos serão primeiros, e os primeiros serão últimos.");
    b->dados[MATEUS].capitulos[20].versos[17] = wxT("Estando Jesus para subir a Jerusalém, chamou à parte os doze e no caminho lhes disse:");
    b->dados[MATEUS].capitulos[20].versos[18] = wxT("Eis que subimos a Jerusalém, e o Filho do homem será entregue aos principais sacerdotes e aos escribas, e eles o condenarão à morte,");
    b->dados[MATEUS].capitulos[20].versos[19] = wxT("e o entregarão aos gentios para que dele escarneçam, e o açoitem e crucifiquem; e ao terceiro dia ressuscitará.");
    b->dados[MATEUS].capitulos[20].versos[20] = wxT("Aproximou-se dele, então, a mãe dos filhos de Zebedeu, com seus filhos, ajoelhando-se e fazendo-lhe um pedido.");
    b->dados[MATEUS].capitulos[20].versos[21] = wxT("Perguntou-lhe Jesus: Que queres? Ela lhe respondeu: Concede que estes meus dois filhos se sentem, um à tua direita e outro à tua esquerda, no teu reino.");
    b->dados[MATEUS].capitulos[20].versos[22] = wxT("Jesus, porém, replicou: Não sabeis o que pedis; podeis beber o cálice que eu estou para beber? Responderam-lhe: Podemos.");
    b->dados[MATEUS].capitulos[20].versos[23] = wxT("Então lhes disse: O meu cálice certamente haveis de beber; mas o sentar-se à minha direita e à minha esquerda, não me pertence concedê-lo; mas isso é para aqueles para quem está preparado por meu Pai.");
    b->dados[MATEUS].capitulos[20].versos[24] = wxT("E ouvindo isso os dez, indignaram-se contra os dois irmãos.");
    b->dados[MATEUS].capitulos[20].versos[25] = wxT("Jesus, pois, chamou-os para junto de si e lhes disse: Sabeis que os governadores dos gentios os dominam, e os seus grandes exercem autoridades sobre eles.");
    b->dados[MATEUS].capitulos[20].versos[26] = wxT("Não será assim entre vós; antes, qualquer que entre vós quiser tornar-se grande, será esse o que vos sirva;");
    b->dados[MATEUS].capitulos[20].versos[27] = wxT("e qualquer que entre vós quiser ser o primeiro, será vosso servo;");
    b->dados[MATEUS].capitulos[20].versos[28] = wxT("assim como o Filho do homem não veio para ser servido, mas para servir, e para dar a sua vida em resgate de muitos.");
    b->dados[MATEUS].capitulos[20].versos[29] = wxT("Saindo eles de Jericó, seguiu-o uma grande multidão;");
    b->dados[MATEUS].capitulos[20].versos[30] = wxT("e eis que dois cegos, sentados junto do caminho, ouvindo que Jesus passava, clamaram, dizendo: Senhor, Filho de Davi, tem compaixão de nós.");
    b->dados[MATEUS].capitulos[20].versos[31] = wxT("E a multidão os repreendeu, para que se calassem; eles, porém, clamaram ainda mais alto, dizendo: Senhor, Filho de Davi, tem compaixão de nós.");
    b->dados[MATEUS].capitulos[20].versos[32] = wxT("E Jesus, parando, chamou-os e perguntou: Que quereis que vos faça?");
    b->dados[MATEUS].capitulos[20].versos[33] = wxT("Disseram-lhe eles: Senhor, que se nos abram os olhos.");
    b->dados[MATEUS].capitulos[20].versos[34] = wxT("E Jesus, movido de compaixão, tocou-lhes os olhos, e imediatamente recuperaram a vista, e o seguiram.");

    b->dados[MATEUS].capitulos[21].versos[1] = wxT("Quando se aproximaram de Jerusalém, e chegaram a Betfagé, ao Monte das Oliveiras, enviou Jesus dois discípulos, dizendo-lhes:");
    b->dados[MATEUS].capitulos[21].versos[2] = wxT("Ide à aldeia que está defronte de vós, e logo encontrareis uma jumenta presa, e um jumentinho com ela; desprendei-a, e trazei-mos.");
    b->dados[MATEUS].capitulos[21].versos[3] = wxT("E, se alguém vos disser alguma coisa, respondei: O Senhor precisa deles; e logo os enviará.");
    b->dados[MATEUS].capitulos[21].versos[4] = wxT("Ora, isso aconteceu para que se cumprisse o que foi dito pelo profeta:");
    b->dados[MATEUS].capitulos[21].versos[5] = wxT("Dizei à filha de Sião: Eis que aí te vem o teu Rei, manso e montado em um jumento, em um jumentinho, cria de animal de carga.");
    b->dados[MATEUS].capitulos[21].versos[6] = wxT("Indo, pois, os discípulos e fazendo como Jesus lhes ordenara,");
    b->dados[MATEUS].capitulos[21].versos[7] = wxT("trouxeram a jumenta e o jumentinho, e sobre eles puseram os seus mantos, e Jesus montou.");
    b->dados[MATEUS].capitulos[21].versos[8] = wxT("E a maior parte da multidão estendeu os seus mantos pelo caminho; e outros cortavam ramos de árvores, e os espalhavam pelo caminho.");
    b->dados[MATEUS].capitulos[21].versos[9] = wxT("E as multidões, tanto as que o precediam como as que o seguiam, clamavam, dizendo: Hosana ao Filho de Davi! bendito o que vem em nome do Senhor! Hosana nas alturas!");
    b->dados[MATEUS].capitulos[21].versos[10] = wxT("Ao entrar ele em Jerusalém, agitou-se a cidade toda e perguntava: Quem é este?");
    b->dados[MATEUS].capitulos[21].versos[11] = wxT("E as multidões respondiam: Este é o profeta Jesus, de Nazaré da Galiléia.");
    b->dados[MATEUS].capitulos[21].versos[12] = wxT("Então Jesus entrou no templo, expulsou todos os que ali vendiam e compravam, e derribou as mesas dos cambistas e as cadeiras dos que vendiam pombas;");
    b->dados[MATEUS].capitulos[21].versos[13] = wxT("e disse-lhes: Está escrito: A minha casa será chamada casa de oração; vós, porém, a fazeis covil de salteadores.");
    b->dados[MATEUS].capitulos[21].versos[14] = wxT("E chegaram-se a ele no templo cegos e coxos, e ele os curou.");
    b->dados[MATEUS].capitulos[21].versos[15] = wxT("Vendo, porém, os principais sacerdotes e os escribas as maravilhas que ele fizera, e os meninos que clamavam no templo: Hosana ao Filho de Davi, indignaram-se,");
    b->dados[MATEUS].capitulos[21].versos[16] = wxT("e perguntaram-lhe: Ouves o que estes estão dizendo? Respondeu-lhes Jesus: Sim; nunca lestes: Da boca de pequeninos e de criancinhas de peito tiraste perfeito louvor?");
    b->dados[MATEUS].capitulos[21].versos[17] = wxT("E deixando-os, saiu da cidade para Betânia, e ali passou a noite.");
    b->dados[MATEUS].capitulos[21].versos[18] = wxT("Ora, de manhã, ao voltar à cidade, teve fome;");
    b->dados[MATEUS].capitulos[21].versos[19] = wxT("e, avistando uma figueira à beira do caminho, dela se aproximou, e não achou nela senão folhas somente; e disse-lhe: Nunca mais nasça fruto de ti. E a figueira secou imediatamente.");
    b->dados[MATEUS].capitulos[21].versos[20] = wxT("Quando os discípulos viram isso, perguntaram admirados: Como é que imediatamente secou a figueira?");
    b->dados[MATEUS].capitulos[21].versos[21] = wxT("Jesus, porém, respondeu-lhes: Em verdade vos digo que, se tiverdes fé e não duvidardes, não só fareis o que foi feito à figueira, mas até, se a este monte disserdes: Ergue-te e lança-te no mar, isso será feito;");
    b->dados[MATEUS].capitulos[21].versos[22] = wxT("e tudo o que pedirdes na oração, crendo, recebereis.");
    b->dados[MATEUS].capitulos[21].versos[23] = wxT("Tendo Jesus entrado no templo, e estando a ensinar, aproximaram-se dele os principais sacerdotes e os anciãos do povo, e perguntaram: Com que autoridade fazes tu estas coisas? e quem te deu tal autoridade?");
    b->dados[MATEUS].capitulos[21].versos[24] = wxT("Respondeu-lhes Jesus: Eu também vos perguntarei uma coisa; se ma disserdes, eu de igual modo vos direi com que autoridade faço estas coisas.");
    b->dados[MATEUS].capitulos[21].versos[25] = wxT("O batismo de João, donde era? do céu ou dos homens? Ao que eles arrazoavam entre si: Se dissermos: Do céu, ele nos dirá: Então por que não o crestes?");
    b->dados[MATEUS].capitulos[21].versos[26] = wxT("Mas, se dissermos: Dos homens, tememos o povo; porque todos consideram João como profeta.");
    b->dados[MATEUS].capitulos[21].versos[27] = wxT("Responderam, pois, a Jesus: Não sabemos. Disse-lhe ele: Nem eu vos digo com que autoridade faço estas coisas.");
    b->dados[MATEUS].capitulos[21].versos[28] = wxT("Mas que vos parece? Um homem tinha dois filhos, e, chegando-se ao primeiro, disse: Filho, vai trabalhar hoje na vinha.");
    b->dados[MATEUS].capitulos[21].versos[29] = wxT("Ele respondeu: Sim, senhor; mas não foi.");
    b->dados[MATEUS].capitulos[21].versos[30] = wxT("Chegando-se, então, ao segundo, falou-lhe de igual modo; respondeu-lhe este: Não quero; mas depois, arrependendo-se, foi.");
    b->dados[MATEUS].capitulos[21].versos[31] = wxT("Qual dos dois fez a vontade do pai? Disseram eles: O segundo. Disse-lhes Jesus: Em verdade vos digo que os publicanos e as meretrizes entram adiante de vós no reino de Deus.");
    b->dados[MATEUS].capitulos[21].versos[32] = wxT("Pois João veio a vós no caminho da justiça, e não lhe deste crédito, mas os publicanos e as meretrizes lho deram; vós, porém, vendo isto, nem depois vos arrependestes para crerdes nele.");
    b->dados[MATEUS].capitulos[21].versos[33] = wxT("Ouvi ainda outra parábola: Havia um homem, proprietário, que plantou uma vinha, cercou-a com uma sebe, cavou nela um lagar, e edificou uma torre; depois arrendou-a a uns lavradores e ausentou-se do país.");
    b->dados[MATEUS].capitulos[21].versos[34] = wxT("E quando chegou o tempo dos frutos, enviou os seus servos aos lavradores, para receber os seus frutos.");
    b->dados[MATEUS].capitulos[21].versos[35] = wxT("E os lavradores, apoderando-se dos servos, espancaram um, mataram outro, e a outro apedrejaram.");
    b->dados[MATEUS].capitulos[21].versos[36] = wxT("Depois enviou ainda outros servos, em maior número do que os primeiros; e fizeram-lhes o mesmo.");
    b->dados[MATEUS].capitulos[21].versos[37] = wxT("Por último enviou-lhes seu filho, dizendo: A meu filho terão respeito.");
    b->dados[MATEUS].capitulos[21].versos[38] = wxT("Mas os lavradores, vendo o filho, disseram entre si: Este é o herdeiro; vinde, matemo-lo, e apoderemo-nos da sua herança.");
    b->dados[MATEUS].capitulos[21].versos[39] = wxT("E, agarrando-o, lançaram-no fora da vinha e o mataram.");
    b->dados[MATEUS].capitulos[21].versos[40] = wxT("Quando, pois, vier o senhor da vinha, que fará àqueles lavradores?");
    b->dados[MATEUS].capitulos[21].versos[41] = wxT("Responderam-lhe eles: Fará perecer miseravelmente a esses maus, e arrendará a vinha a outros lavradores, que a seu tempo lhe entreguem os frutos.");
    b->dados[MATEUS].capitulos[21].versos[42] = wxT("Disse-lhes Jesus: Nunca lestes nas Escrituras: A pedra que os edificadores rejeitaram, essa foi posta como pedra angular; pelo Senhor foi feito isso, e é maravilhoso aos nossos olhos?");
    b->dados[MATEUS].capitulos[21].versos[43] = wxT("Portanto eu vos digo que vos será tirado o reino de Deus, e será dado a um povo que dê os seus frutos.");
    b->dados[MATEUS].capitulos[21].versos[44] = wxT("E quem cair sobre esta pedra será despedaçado; mas aquele sobre quem ela cair será reduzido a pó.");
    b->dados[MATEUS].capitulos[21].versos[45] = wxT("Os principais sacerdotes e os fariseus, ouvindo essas parábolas, entenderam que era deles que Jesus falava.");
    b->dados[MATEUS].capitulos[21].versos[46] = wxT("E procuravam prendê-lo, mas temeram o povo, porquanto este o tinha por profeta.");

    b->dados[MATEUS].capitulos[22].versos[1] = wxT("Então Jesus tornou a falar-lhes por parábolas, dizendo:");
    b->dados[MATEUS].capitulos[22].versos[2] = wxT("O reino dos céus é semelhante a um rei, que celebrou as bodas de seu filho.");
    b->dados[MATEUS].capitulos[22].versos[3] = wxT("Enviou os seus servos a chamar os convidados para a festa, e estes não quiseram vir.");
    b->dados[MATEUS].capitulos[22].versos[4] = wxT("Enviou ainda outros servos com este recado: Dizei aos convidados: Tenho já preparado o meu banquete; as minhas reses e os meus cevados estão mortos, e tudo está pronto; vinde às bodas.");
    b->dados[MATEUS].capitulos[22].versos[5] = wxT("Mas eles não fizeram caso e foram, um para o seu campo, outro para o seu negócio;");
    b->dados[MATEUS].capitulos[22].versos[6] = wxT("e os outros, agarrando os servos, os ultrajaram e mataram.");
    b->dados[MATEUS].capitulos[22].versos[7] = wxT("Irou-se o rei, e mandou as suas tropas exterminar aqueles assassinos e incendiar a sua cidade.");
    b->dados[MATEUS].capitulos[22].versos[8] = wxT("Então disse aos servos: As bodas estão preparadas, mas os convidados não eram dignos;");
    b->dados[MATEUS].capitulos[22].versos[9] = wxT("ide, pois, às encruzilhadas dos caminhos e chamai para as bodas a quantos encontrardes.");
    b->dados[MATEUS].capitulos[22].versos[10] = wxT("Indo aqueles servos pelos caminhos, reuniram todos os que encontraram, maus e bons; e a sala nupcial ficou cheia de convivas.");
    b->dados[MATEUS].capitulos[22].versos[11] = wxT("Mas entrando o rei para ver os convivas, notou ali um homem que não trajava veste nupcial,");
    b->dados[MATEUS].capitulos[22].versos[12] = wxT("e perguntou-lhe: Amigo, como entraste aqui sem veste nupcial? Ele, porém, emudeceu.");
    b->dados[MATEUS].capitulos[22].versos[13] = wxT("Então o rei disse aos servos: Atai-o de pés e mãos, e lançai-o nas trevas exteriores; ali haverá o choro e o ranger de dentes.");
    b->dados[MATEUS].capitulos[22].versos[14] = wxT("Pois muitos são chamados, mas poucos escolhidos.");
    b->dados[MATEUS].capitulos[22].versos[15] = wxT("Então os fariseus se retiraram e consultaram entre si como o apanhariam em alguma palavra;");
    b->dados[MATEUS].capitulos[22].versos[16] = wxT("Enviaram os seus discípulos, juntamente com os herodianos, a perguntar: Mestre, sabemos que és verdadeiro e que ensinas o caminho de Deus segundo a verdade, e não se te dá de ninguém, porque não te deixas levar de respeitos humanos;");
    b->dados[MATEUS].capitulos[22].versos[17] = wxT("dize-nos, pois, qual é o teu parecer; é lícito ou não pagar o tributo a César?");
    b->dados[MATEUS].capitulos[22].versos[18] = wxT("Porém Jesus, tendo percebido a malícia deles, respondeu-lhes: Por que me experimentais, hipócritas?");
    b->dados[MATEUS].capitulos[22].versos[19] = wxT("Mostrai-me uma moeda de tributo. Trouxeram-lhe um denário.");
    b->dados[MATEUS].capitulos[22].versos[20] = wxT("Ele perguntou: De quem é esta efígie e inscrição?");
    b->dados[MATEUS].capitulos[22].versos[21] = wxT("Responderam: De César. Então lhes disse Jesus: Dai, pois, a César o que é de César, e a Deus o que é de Deus.");
    b->dados[MATEUS].capitulos[22].versos[22] = wxT("Ao ouvirem isto, admiraram-se e, deixando-o, foram-se.");
    b->dados[MATEUS].capitulos[22].versos[23] = wxT("No mesmo dia vieram alguns saduceus, que dizem não haver ressurreição, e o interrogaram, dizendo:");
    b->dados[MATEUS].capitulos[22].versos[24] = wxT("Mestre, Moisés disse: Se alguém morrer sem deixar filhos, seu irmão casará com a viúva e dará sucessão ao falecido.");
    b->dados[MATEUS].capitulos[22].versos[25] = wxT("Ora havia entre nós sete irmãos: o primeiro, depois de ter casado, morreu e, não havendo sucessão, deixou sua mulher a seu irmão;");
    b->dados[MATEUS].capitulos[22].versos[26] = wxT("do mesmo modo também o segundo e o terceiro, até o sétimo.");
    b->dados[MATEUS].capitulos[22].versos[27] = wxT("Depois de todos eles morreu a mulher.");
    b->dados[MATEUS].capitulos[22].versos[28] = wxT("Na ressurreição, pois, a qual dos sete pertencerá a mulher? porque todos foram casados com ela.");
    b->dados[MATEUS].capitulos[22].versos[29] = wxT("Respondeu-lhes Jesus: Errais, não sabendo as Escrituras, nem o poder de Deus.");
    b->dados[MATEUS].capitulos[22].versos[30] = wxT("Pois na ressurreição nem os homens casam, nem as mulheres são dadas em casamento porém são como os anjos no céu.");
    b->dados[MATEUS].capitulos[22].versos[31] = wxT("E, quanto à ressurreição dos mortos, não lestes o que foi dito por Deus:");
    b->dados[MATEUS].capitulos[22].versos[32] = wxT("Eu sou o Deus de Abraão, o Deus de Isaque, e o Deus de Jacó? Ora, ele não é Deus de mortos, mas de vivos.");
    b->dados[MATEUS].capitulos[22].versos[33] = wxT("E as multidões, ouvindo isso, se maravilhavam da sua doutrina.");
    b->dados[MATEUS].capitulos[22].versos[34] = wxT("Os fariseus, quando souberam, que ele fizera emudecer os saduceus, reuniram-se todos;");
    b->dados[MATEUS].capitulos[22].versos[35] = wxT("e um deles, doutor da lei, para o experimentar, interrogou-o, dizendo:");
    b->dados[MATEUS].capitulos[22].versos[36] = wxT("Mestre, qual é o grande mandamento na lei?");
    b->dados[MATEUS].capitulos[22].versos[37] = wxT("Respondeu-lhe Jesus: Amarás ao Senhor teu Deus de todo o teu coração, de toda a tua alma, e de todo o teu entendimento.");
    b->dados[MATEUS].capitulos[22].versos[38] = wxT("Este é o grande e primeiro mandamento.");
    b->dados[MATEUS].capitulos[22].versos[39] = wxT("E o segundo, semelhante a este, é: Amarás ao teu próximo como a ti mesmo.");
    b->dados[MATEUS].capitulos[22].versos[40] = wxT("Destes dois mandamentos dependem toda a lei e os profetas.");
    b->dados[MATEUS].capitulos[22].versos[41] = wxT("Ora, enquanto os fariseus estavam reunidos, interrogou-os Jesus, dizendo:");
    b->dados[MATEUS].capitulos[22].versos[42] = wxT("Que pensais vós do Cristo? De quem é filho? Responderam-lhe: De Davi.");
    b->dados[MATEUS].capitulos[22].versos[43] = wxT("Replicou-lhes ele: Como é então que Davi, no Espírito, lhe chama Senhor, dizendo:");
    b->dados[MATEUS].capitulos[22].versos[44] = wxT("Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos de baixo dos teus pés?");
    b->dados[MATEUS].capitulos[22].versos[45] = wxT("Se Davi, pois, lhe chama Senhor, como é ele seu filho?");
    b->dados[MATEUS].capitulos[22].versos[46] = wxT("E ninguém podia responder-lhe palavra; nem desde aquele dia jamais ousou alguém interrogá-lo.");

    b->dados[MATEUS].capitulos[23].versos[1] = wxT("Então falou Jesus às multidões e aos seus discípulos, dizendo:");
    b->dados[MATEUS].capitulos[23].versos[2] = wxT("Na cadeira de Moisés se assentam os escribas e fariseus.");
    b->dados[MATEUS].capitulos[23].versos[3] = wxT("Portanto, tudo o que vos disserem, isso fazei e observai; mas não façais conforme as suas obras; porque dizem e não praticam.");
    b->dados[MATEUS].capitulos[23].versos[4] = wxT("Pois atam fardos pesados e difíceis de suportar, e os põem aos ombros dos homens; mas eles mesmos nem com o dedo querem movê-los.");
    b->dados[MATEUS].capitulos[23].versos[5] = wxT("Todas as suas obras eles fazem a fim de serem vistos pelos homens; pois alargam os seus filactérios, e aumentam as franjas dos seus mantos;");
    b->dados[MATEUS].capitulos[23].versos[6] = wxT("gostam do primeiro lugar nos banquetes, das primeiras cadeiras nas sinagogas,");
    b->dados[MATEUS].capitulos[23].versos[7] = wxT("das saudações nas praças, e de serem chamados pelos homens: Rabi.");
    b->dados[MATEUS].capitulos[23].versos[8] = wxT("Vós, porém, não queirais ser chamados Rabi; porque um só é o vosso Mestre, e todos vós sois irmãos.");
    b->dados[MATEUS].capitulos[23].versos[9] = wxT("E a ninguém sobre a terra chameis vosso pai; porque um só é o vosso Pai, aquele que está nos céus.");
    b->dados[MATEUS].capitulos[23].versos[10] = wxT("Nem queirais ser chamados guias; porque um só é o vosso Guia, que é o Cristo.");
    b->dados[MATEUS].capitulos[23].versos[11] = wxT("Mas o maior dentre vós há de ser vosso servo.");
    b->dados[MATEUS].capitulos[23].versos[12] = wxT("Qualquer, pois, que a si mesmo se exaltar, será humilhado; e qualquer que a si mesmo se humilhar, será exaltado.");
    b->dados[MATEUS].capitulos[23].versos[13] = wxT("Mas ai de vós, escribas e fariseus, hipócritas! porque fechais aos homens o reino dos céus; pois nem vós entrais, nem aos que entrariam permitis entrar.");
    b->dados[MATEUS].capitulos[23].versos[14] = wxT("{Ai de vós, escribas e fariseus, hipócritas! porque devorais as casas das viúvas e sob pretexto fazeis longas orações; por isso recebereis maior condenação.}");
    b->dados[MATEUS].capitulos[23].versos[15] = wxT("Ai de vós, escribas e fariseus, hipócritas! porque percorreis o mar e a terra para fazer um prosélito; e, depois de o terdes feito, o tornais duas vezes mais filho do inferno do que vós.");
    b->dados[MATEUS].capitulos[23].versos[16] = wxT("Ai de vós, guias cegos! que dizeis: Quem jurar pelo ouro do santuário, esse fica obrigado ao que jurou.");
    b->dados[MATEUS].capitulos[23].versos[17] = wxT("Insensatos e cegos! Pois qual é o maior; o ouro, ou o santuário que santifica o ouro?");
    b->dados[MATEUS].capitulos[23].versos[18] = wxT("E: Quem jurar pelo altar, isso nada é; mas quem jurar pela oferta que está sobre o altar, esse fica obrigado ao que jurou.");
    b->dados[MATEUS].capitulos[23].versos[19] = wxT("Cegos! Pois qual é maior: a oferta, ou o altar que santifica a oferta?");
    b->dados[MATEUS].capitulos[23].versos[20] = wxT("Portanto, quem jurar pelo altar jura por ele e por tudo quanto sobre ele está;");
    b->dados[MATEUS].capitulos[23].versos[21] = wxT("e quem jurar pelo santuário jura por ele e por aquele que nele habita;");
    b->dados[MATEUS].capitulos[23].versos[22] = wxT("e quem jurar pelo céu jura pelo trono de Deus e por aquele que nele está assentado.");
    b->dados[MATEUS].capitulos[23].versos[23] = wxT("Ai de vós, escribas e fariseus, hipócritas! porque dais o dízimo da hortelã, do endro e do cominho, e tendes omitido o que há de mais importante na lei, a saber, a justiça, a misericórdia e a fé; estas coisas, porém, devíeis fazer, sem omitir aquelas.");
    b->dados[MATEUS].capitulos[23].versos[24] = wxT("Guias cegos! que coais um mosquito, e engolis um camelo.");
    b->dados[MATEUS].capitulos[23].versos[25] = wxT("Ai de vós, escribas e fariseus, hipócritas! porque limpais o exterior do copo e do prato, mas por dentro estão cheios de rapina e de intemperança.");
    b->dados[MATEUS].capitulos[23].versos[26] = wxT("Fariseu cego! limpa primeiro o interior do copo, para que também o exterior se torne limpo.");
    b->dados[MATEUS].capitulos[23].versos[27] = wxT("Ai de vós, escribas e fariseus, hipócritas! porque sois semelhantes aos sepulcros caiados, que por fora realmente parecem formosos, mas por dentro estão cheios de ossos e de toda imundícia.");
    b->dados[MATEUS].capitulos[23].versos[28] = wxT("Assim também vós exteriormente pareceis justos aos homens, mas por dentro estais cheios de hipocrisia e de iniqüidade.");
    b->dados[MATEUS].capitulos[23].versos[29] = wxT("Ai de vós, escribas e fariseus, hipócritas! porque edificais os sepulcros dos profetas e adornais os monumentos dos justos,");
    b->dados[MATEUS].capitulos[23].versos[30] = wxT("e dizeis: Se tivéssemos vivido nos dias de nossos pais, não teríamos sido cúmplices no derramar o sangue dos profetas.");
    b->dados[MATEUS].capitulos[23].versos[31] = wxT("Assim, vós testemunhais contra vós mesmos que sois filhos daqueles que mataram os profetas.");
    b->dados[MATEUS].capitulos[23].versos[32] = wxT("Enchei vós, pois, a medida de vossos pais.");
    b->dados[MATEUS].capitulos[23].versos[33] = wxT("Serpentes, raça de víboras! como escapareis da condenação do inferno?");
    b->dados[MATEUS].capitulos[23].versos[34] = wxT("Portanto, eis que eu vos envio profetas, sábios e escribas: e a uns deles matareis e crucificareis; e a outros os perseguireis de cidade em cidade;");
    b->dados[MATEUS].capitulos[23].versos[35] = wxT("para que sobre vós caia todo o sangue justo, que foi derramado sobre a terra, desde o sangue de Abel, o justo, até o sangue de Zacarias, filho de Baraquias, que mataste entre o santuário e o altar.");
    b->dados[MATEUS].capitulos[23].versos[36] = wxT("Em verdade vos digo que todas essas coisas hão de vir sobre esta geração.");
    b->dados[MATEUS].capitulos[23].versos[37] = wxT("Jerusalém, Jerusalém, que matas os profetas, apedrejas os que a ti são enviados! quantas vezes quis eu ajuntar os teus filhos, como a galinha ajunta os seus pintos debaixo das asas, e não o quiseste!");
    b->dados[MATEUS].capitulos[23].versos[38] = wxT("Eis aí abandonada vos é a vossa casa.");
    b->dados[MATEUS].capitulos[23].versos[39] = wxT("Pois eu vos declaro que desde agora de modo nenhum me vereis, até que digais: Bendito aquele que vem em nome do Senhor.");

    b->dados[MATEUS].capitulos[24].versos[1] = wxT("Ora, Jesus, tendo saído do templo, ia-se retirando, quando se aproximaram dele os seus discípulos, para lhe mostrarem os edifícios do templo.");
    b->dados[MATEUS].capitulos[24].versos[2] = wxT("Mas ele lhes disse: Não vedes tudo isto? Em verdade vos digo que não se deixará aqui pedra sobre pedra que não seja derribada.");
    b->dados[MATEUS].capitulos[24].versos[3] = wxT("E estando ele sentado no Monte das Oliveiras, chegaram-se a ele os seus discípulos em particular, dizendo: Declara-nos quando serão essas coisas, e que sinal haverá da tua vinda e do fim do mundo.");
    b->dados[MATEUS].capitulos[24].versos[4] = wxT("Respondeu-lhes Jesus: Acautelai-vos, que ninguém vos engane.");
    b->dados[MATEUS].capitulos[24].versos[5] = wxT("Porque muitos virão em meu nome, dizendo: Eu sou o Cristo; a muitos enganarão.");
    b->dados[MATEUS].capitulos[24].versos[6] = wxT("E ouvireis falar de guerras e rumores de guerras; olhai não vos perturbeis; porque forçoso é que assim aconteça; mas ainda não é o fim.");
    b->dados[MATEUS].capitulos[24].versos[7] = wxT("Porquanto se levantará nação contra nação, e reino contra reino; e haverá fomes e terremotos em vários lugares.");
    b->dados[MATEUS].capitulos[24].versos[8] = wxT("Mas todas essas coisas são o princípio das dores.");
    b->dados[MATEUS].capitulos[24].versos[9] = wxT("Então sereis entregues à tortura, e vos matarão; e sereis odiados de todas as nações por causa do meu nome.");
    b->dados[MATEUS].capitulos[24].versos[10] = wxT("Nesse tempo muitos hão de se escandalizar, e trair-se uns aos outros, e mutuamente se odiarão.");
    b->dados[MATEUS].capitulos[24].versos[11] = wxT("Igualmente hão de surgir muitos falsos profetas, e enganarão a muitos;");
    b->dados[MATEUS].capitulos[24].versos[12] = wxT("e, por se multiplicar a iniqüidade, o amor de muitos esfriará.");
    b->dados[MATEUS].capitulos[24].versos[13] = wxT("Mas quem perseverar até o fim, esse será salvo.");
    b->dados[MATEUS].capitulos[24].versos[14] = wxT("E este evangelho do reino será pregado no mundo inteiro, em testemunho a todas as nações, e então virá o fim.");
    b->dados[MATEUS].capitulos[24].versos[15] = wxT("Quando, pois, virdes estar no lugar santo a abominação de desolação, predita pelo profeta Daniel {quem lê, entenda},");
    b->dados[MATEUS].capitulos[24].versos[16] = wxT("então os que estiverem na Judéia fujam para os montes;");
    b->dados[MATEUS].capitulos[24].versos[17] = wxT("quem estiver no eirado não desça para tirar as coisas de sua casa,");
    b->dados[MATEUS].capitulos[24].versos[18] = wxT("e quem estiver no campo não volte atrás para apanhar a sua capa.");
    b->dados[MATEUS].capitulos[24].versos[19] = wxT("Mas ai das que estiverem grávidas, e das que amamentarem naqueles dias!");
    b->dados[MATEUS].capitulos[24].versos[20] = wxT("Orai para que a vossa fuga não suceda no inverno nem no sábado;");
    b->dados[MATEUS].capitulos[24].versos[21] = wxT("porque haverá então uma tribulação tão grande, como nunca houve desde o princípio do mundo até agora, nem jamais haverá.");
    b->dados[MATEUS].capitulos[24].versos[22] = wxT("E se aqueles dias não fossem abreviados, ninguém se salvaria; mas por causa dos escolhidos serão abreviados aqueles dias.");
    b->dados[MATEUS].capitulos[24].versos[23] = wxT("Se, pois, alguém vos disser: Eis aqui o Cristo! ou: Ei-lo aí! não acrediteis;");
    b->dados[MATEUS].capitulos[24].versos[24] = wxT("porque hão de surgir falsos cristos e falsos profetas, e farão grandes sinais e prodígios; de modo que, se possível fora, enganariam até os escolhidos.");
    b->dados[MATEUS].capitulos[24].versos[25] = wxT("Eis que de antemão vo-lo tenho dito.");
    b->dados[MATEUS].capitulos[24].versos[26] = wxT("Portanto, se vos disserem: Eis que ele está no deserto; não saiais; ou: Eis que ele está no interior da casa; não acrediteis.");
    b->dados[MATEUS].capitulos[24].versos[27] = wxT("Porque, assim como o relâmpago sai do oriente e se mostra até o ocidente, assim será também a vinda do filho do homem.");
    b->dados[MATEUS].capitulos[24].versos[28] = wxT("Pois onde estiver o cadáver, aí se ajuntarão os abutres.");
    b->dados[MATEUS].capitulos[24].versos[29] = wxT("Logo depois da tribulação daqueles dias, escurecerá o sol, e a lua não dará a sua luz; as estrelas cairão do céu e os poderes dos céus serão abalados.");
    b->dados[MATEUS].capitulos[24].versos[30] = wxT("Então aparecerá no céu o sinal do Filho do homem, e todas as tribos da terra se lamentarão, e verão vir o Filho do homem sobre as nuvens do céu, com poder e grande glória.");
    b->dados[MATEUS].capitulos[24].versos[31] = wxT("E ele enviará os seus anjos com grande clangor de trombeta, os quais lhe ajuntarão os escolhidos desde os quatro ventos, de uma à outra extremidade dos céus.");
    b->dados[MATEUS].capitulos[24].versos[32] = wxT("Aprendei, pois, da figueira a sua parábola: Quando já o seu ramo se torna tenro e brota folhas, sabeis que está próximo o verão.");
    b->dados[MATEUS].capitulos[24].versos[33] = wxT("Igualmente, quando virdes todas essas coisas, sabei que ele está próximo, mesmo às portas.");
    b->dados[MATEUS].capitulos[24].versos[34] = wxT("Em verdade vos digo que não passará esta geração sem que todas essas coisas se cumpram.");
    b->dados[MATEUS].capitulos[24].versos[35] = wxT("Passará o céu e a terra, mas as minhas palavras jamais passarão.");
    b->dados[MATEUS].capitulos[24].versos[36] = wxT("Daquele dia e hora, porém, ninguém sabe, nem os anjos do céu, nem o Filho, senão só o Pai.");
    b->dados[MATEUS].capitulos[24].versos[37] = wxT("Pois como foi dito nos dias de Noé, assim será também a vinda do Filho do homem.");
    b->dados[MATEUS].capitulos[24].versos[38] = wxT("Porquanto, assim como nos dias anteriores ao dilúvio, comiam, bebiam, casavam e davam-se em casamento, até o dia em que Noé entrou na arca,");
    b->dados[MATEUS].capitulos[24].versos[39] = wxT("e não o perceberam, até que veio o dilúvio, e os levou a todos; assim será também a vinda do Filho do homem.");
    b->dados[MATEUS].capitulos[24].versos[40] = wxT("Então, estando dois homens no campo, será levado um e deixado outro;");
    b->dados[MATEUS].capitulos[24].versos[41] = wxT("estando duas mulheres a trabalhar no moinho, será levada uma e deixada a outra.");
    b->dados[MATEUS].capitulos[24].versos[42] = wxT("Vigiai, pois, porque não sabeis em que dia vem o vosso Senhor;");
    b->dados[MATEUS].capitulos[24].versos[43] = wxT("sabei, porém, isto: se o dono da casa soubesse a que vigília da noite havia de vir o ladrão, vigiaria e não deixaria minar a sua casa.");
    b->dados[MATEUS].capitulos[24].versos[44] = wxT("Por isso ficai também vós apercebidos; porque numa hora em que não penseis, virá o Filho do homem.");
    b->dados[MATEUS].capitulos[24].versos[45] = wxT("Quem é, pois, o servo fiel e prudente, que o senhor pôs sobre os seus serviçais, para a tempo dar-lhes o sustento?");
    b->dados[MATEUS].capitulos[24].versos[46] = wxT("Bem-aventurado aquele servo a quem o seu senhor, quando vier, achar assim fazendo.");
    b->dados[MATEUS].capitulos[24].versos[47] = wxT("Em verdade vos digo que o porá sobre todos os seus bens.");
    b->dados[MATEUS].capitulos[24].versos[48] = wxT("Mas se aquele outro, o mau servo, disser no seu coração: Meu senhor tarda em vir,");
    b->dados[MATEUS].capitulos[24].versos[49] = wxT("e começar a espancar os seus conservos, e a comer e beber com os ébrios,");
    b->dados[MATEUS].capitulos[24].versos[50] = wxT("virá o senhor daquele servo, num dia em que não o espera, e numa hora de que não sabe,");
    b->dados[MATEUS].capitulos[24].versos[51] = wxT("e cortá-lo-á pelo meio, e lhe dará a sua parte com os hipócritas; ali haverá choro e ranger de dentes.");

    b->dados[MATEUS].capitulos[25].versos[1] = wxT("Então o reino dos céus será semelhante a dez virgens que, tomando as suas lâmpadas, saíram ao encontro do noivo.");
    b->dados[MATEUS].capitulos[25].versos[2] = wxT("Cinco delas eram insensatas, e cinco prudentes.");
    b->dados[MATEUS].capitulos[25].versos[3] = wxT("Ora, as insensatas, tomando as lâmpadas, não levaram azeite consigo.");
    b->dados[MATEUS].capitulos[25].versos[4] = wxT("As prudentes, porém, levaram azeite em suas vasilhas, juntamente com as lâmpadas.");
    b->dados[MATEUS].capitulos[25].versos[5] = wxT("E tardando o noivo, cochilaram todas, e dormiram.");
    b->dados[MATEUS].capitulos[25].versos[6] = wxT("Mas à meia-noite ouviu-se um grito: Eis o noivo! saí-lhe ao encontro!");
    b->dados[MATEUS].capitulos[25].versos[7] = wxT("Então todas aquelas virgens se levantaram, e prepararam as suas lâmpadas.");
    b->dados[MATEUS].capitulos[25].versos[8] = wxT("E as insensatas disseram às prudentes: Dai-nos do vosso azeite, porque as nossas lâmpadas estão se apagando.");
    b->dados[MATEUS].capitulos[25].versos[9] = wxT("Mas as prudentes responderam: não; pois de certo não chegaria para nós e para vós; ide antes aos que o vendem, e comprai-o para vós.");
    b->dados[MATEUS].capitulos[25].versos[10] = wxT("E, tendo elas ido comprá-lo, chegou o noivo; e as que estavam preparadas entraram com ele para as bodas, e fechou-se a porta.");
    b->dados[MATEUS].capitulos[25].versos[11] = wxT("Depois vieram também as outras virgens, e disseram: Senhor, Senhor, abre-nos a porta.");
    b->dados[MATEUS].capitulos[25].versos[12] = wxT("Ele, porém, respondeu: Em verdade vos digo, não vos conheço.");
    b->dados[MATEUS].capitulos[25].versos[13] = wxT("Vigiai pois, porque não sabeis nem o dia nem a hora.");
    b->dados[MATEUS].capitulos[25].versos[14] = wxT("Porque é assim como um homem que, ausentando-se do país, chamou os seus servos e lhes entregou os seus bens:");
    b->dados[MATEUS].capitulos[25].versos[15] = wxT("a um deu cinco talentos, a outro dois, e a outro um, a cada um segundo a sua capacidade; e seguiu viagem.");
    b->dados[MATEUS].capitulos[25].versos[16] = wxT("O que recebera cinco talentos foi imediatamente negociar com eles, e ganhou outros cinco;");
    b->dados[MATEUS].capitulos[25].versos[17] = wxT("da mesma sorte, o que recebera dois ganhou outros dois;");
    b->dados[MATEUS].capitulos[25].versos[18] = wxT("mas o que recebera um foi e cavou na terra e escondeu o dinheiro do seu senhor.");
    b->dados[MATEUS].capitulos[25].versos[19] = wxT("Ora, depois de muito tempo veio o senhor daqueles servos, e fez contas com eles.");
    b->dados[MATEUS].capitulos[25].versos[20] = wxT("Então chegando o que recebera cinco talentos, apresentou-lhe outros cinco talentos, dizendo: Senhor, entregaste-me cinco talentos; eis aqui outros cinco que ganhei.");
    b->dados[MATEUS].capitulos[25].versos[21] = wxT("Disse-lhe o seu senhor: Muito bem, servo bom e fiel; sobre o pouco foste fiel, sobre muito te colocarei; entra no gozo do teu senhor.");
    b->dados[MATEUS].capitulos[25].versos[22] = wxT("Chegando também o que recebera dois talentos, disse: Senhor, entregaste-me dois talentos; eis aqui outros dois que ganhei.");
    b->dados[MATEUS].capitulos[25].versos[23] = wxT("Disse-lhe o seu senhor: Muito bem, servo bom e fiel; sobre o pouco foste fiel, sobre muito te colocarei; entra no gozo do teu senhor.");
    b->dados[MATEUS].capitulos[25].versos[24] = wxT("Chegando por fim o que recebera um talento, disse: Senhor, eu te conhecia, que és um homem duro, que ceifas onde não semeaste, e recolhes onde não joeiraste;");
    b->dados[MATEUS].capitulos[25].versos[25] = wxT("e, atemorizado, fui esconder na terra o teu talento; eis aqui tens o que é teu.");
    b->dados[MATEUS].capitulos[25].versos[26] = wxT("Ao que lhe respondeu o seu senhor: Servo mau e preguiçoso, sabias que ceifo onde não semeei, e recolho onde não joeirei?");
    b->dados[MATEUS].capitulos[25].versos[27] = wxT("Devias então entregar o meu dinheiro aos banqueiros e, vindo eu, tê-lo-ia recebido com juros.");
    b->dados[MATEUS].capitulos[25].versos[28] = wxT("Tirai-lhe, pois, o talento e dai ao que tem os dez talentos.");
    b->dados[MATEUS].capitulos[25].versos[29] = wxT("Porque a todo o que tem, dar-se-lhe-á, e terá em abundância; mas ao que não tem, até aquilo que tem ser-lhe-á tirado.");
    b->dados[MATEUS].capitulos[25].versos[30] = wxT("E lançai o servo inútil nas trevas exteriores; ali haverá choro e ranger de dentes.");
    b->dados[MATEUS].capitulos[25].versos[31] = wxT("Quando, pois vier o Filho do homem na sua glória, e todos os anjos com ele, então se assentará no trono da sua glória;");
    b->dados[MATEUS].capitulos[25].versos[32] = wxT("e diante dele serão reunidas todas as nações; e ele separará uns dos outros, como o pastor separa as ovelhas dos cabritos;");
    b->dados[MATEUS].capitulos[25].versos[33] = wxT("e porá as ovelhas à sua direita, mas os cabritos à esquerda.");
    b->dados[MATEUS].capitulos[25].versos[34] = wxT("Então dirá o Rei aos que estiverem à sua direita: Vinde, benditos de meu Pai. Possuí por herança o reino que vos está preparado desde a fundação do mundo;");
    b->dados[MATEUS].capitulos[25].versos[35] = wxT("Pois tive fome, e destes-me de comer; tive sede, e destes-me de beber; era forasteiro, e recolhestes-me;");
    b->dados[MATEUS].capitulos[25].versos[36] = wxT("estava nu, e vestistes-me; enfermo, e visitastes-me; preso, e viestes ver-me.");
    b->dados[MATEUS].capitulos[25].versos[37] = wxT("Então perguntarão os justos: Senhor, quando te vimos faminto, e te demos de comer; ou com sede, e te demos de beber?");
    b->dados[MATEUS].capitulos[25].versos[38] = wxT("Quando te vimos forasteiro, e te recolhemos; ou nu, e te vestimos?");
    b->dados[MATEUS].capitulos[25].versos[39] = wxT("Quando te vimos enfermo, ou preso, e fomos visitar-te?");
    b->dados[MATEUS].capitulos[25].versos[40] = wxT("O Rei responderá: Em verdade vos digo que quantas vezes o fizestes a um destes meus irmãos mais pequeninos, a mim o fizestes.");
    b->dados[MATEUS].capitulos[25].versos[41] = wxT("Dirá também aos que estiverem à sua esquerda: Apartai-vos de mim, malditos, para o fogo eterno, destinado ao Diabo e seus anjos.");
    b->dados[MATEUS].capitulos[25].versos[42] = wxT("Pois tive fome, e não me destes de comer; tive sede e não me destes de beber;");
    b->dados[MATEUS].capitulos[25].versos[43] = wxT("era forasteiro, e não me recolhestes; estava nu, e não me vestistes; enfermo e preso, e não me visitastes.");
    b->dados[MATEUS].capitulos[25].versos[44] = wxT("Também eles perguntarão: Senhor, quando te vimos faminto, com sede, forasteiro, nu, enfermo, ou preso, e não te servimos?");
    b->dados[MATEUS].capitulos[25].versos[45] = wxT("Então lhes responderá: Em verdade vos digo que quantas vezes o deixastes de fazer a um destes mais pequeninos, a mim o deixastes de fazer.");
    b->dados[MATEUS].capitulos[25].versos[46] = wxT("Irão estes para o suplício eterno, porém os justos para a vida eterna.");

    b->dados[MATEUS].capitulos[26].versos[1] = wxT("E havendo Jesus concluído todas estas palavras, disse aos seus discípulos:");
    b->dados[MATEUS].capitulos[26].versos[2] = wxT("Sabeis que de hoje a dois dias celebrar-se-á a páscoa, e o Filho do homem será entregue para ser crucificado.");
    b->dados[MATEUS].capitulos[26].versos[3] = wxT("Depois se reuniram os principais sacerdotes e os anciãos do povo no pátio da casa do sumo sacerdote, chamado Caifás;");
    b->dados[MATEUS].capitulos[26].versos[4] = wxT("e deliberaram prender a Jesus à traição e tirar-lhe a vida.");
    b->dados[MATEUS].capitulos[26].versos[5] = wxT("Mas diziam: Durante a festa, não; para que não haja tumulto entre o povo.");
    b->dados[MATEUS].capitulos[26].versos[6] = wxT("Estando Jesus em Betânia, em casa de Simão, o leproso,");
    b->dados[MATEUS].capitulos[26].versos[7] = wxT("chegou-se a ele uma mulher que trazia um vaso de alabastro com precioso perfume, e lho derramou sobre a cabeça, quando ele estava à mesa.");
    b->dados[MATEUS].capitulos[26].versos[8] = wxT("Vendo isto, seus discípulos indignaram-se e disseram:");
    b->dados[MATEUS].capitulos[26].versos[9] = wxT("Para que este desperdício? Pois o perfume podia ser vendido por muito dinheiro, e ser este dado aos pobres.");
    b->dados[MATEUS].capitulos[26].versos[10] = wxT("Mas Jesus, percebendo isto, disse-lhes: Por que molestais essa mulher? ela me fez uma boa obra.");
    b->dados[MATEUS].capitulos[26].versos[11] = wxT("Pois os pobres sempre os tendes convosco, mas a mim nem sempre me tendes;");
    b->dados[MATEUS].capitulos[26].versos[12] = wxT("derramando ela este perfume sobre o meu corpo, fê-lo para a minha sepultura.");
    b->dados[MATEUS].capitulos[26].versos[13] = wxT("Em verdade vos digo que onde quer que for pregado em todo o mundo este Evangelho, será também contado para memória sua o que ela fez.");
    b->dados[MATEUS].capitulos[26].versos[14] = wxT("Então um dos doze, chamado Judas Iscariotes, foi ter com os principais sacerdotes,");
    b->dados[MATEUS].capitulos[26].versos[15] = wxT("e lhes disse: Que me quereis dar e eu vo-lo entregarei? Eles lhe pesaram trinta moedas de prata.");
    b->dados[MATEUS].capitulos[26].versos[16] = wxT("Desde então Judas buscava oportunidade para o entregar.");
    b->dados[MATEUS].capitulos[26].versos[17] = wxT("Ora, no primeiro dia dos pães ázimos, vieram os discípulos a Jesus, e perguntaram: Onde queres que façamos os preparativos para comeres a páscoa?");
    b->dados[MATEUS].capitulos[26].versos[18] = wxT("Respondeu-lhes: Ide à cidade ter com certo homem, e dizei-lhe que o Mestre diz: O meu tempo está próximo; em tua casa celebrarei a páscoa com meus discípulos.");
    b->dados[MATEUS].capitulos[26].versos[19] = wxT("Eles fizeram como Jesus lhes havia ordenado, e prepararam a páscoa.");
    b->dados[MATEUS].capitulos[26].versos[20] = wxT("À tarde estava ele sentado à mesa com os doze discípulos.");
    b->dados[MATEUS].capitulos[26].versos[21] = wxT("Enquanto comiam, declarou Jesus: Em verdade vos digo que um de vós me trairá.");
    b->dados[MATEUS].capitulos[26].versos[22] = wxT("Eles, muitíssimo contristados, começaram um por um a perguntar-lhe: Porventura sou eu, Senhor?");
    b->dados[MATEUS].capitulos[26].versos[23] = wxT("Ele respondeu: O que põe comigo a mão no prato, esse é o que me trairá.");
    b->dados[MATEUS].capitulos[26].versos[24] = wxT("O Filho do homem vai-se, segundo está escrito a seu respeito, mas ai daquele por quem o Filho do homem é traído! melhor fora para esse homem se não houvesse nascido.");
    b->dados[MATEUS].capitulos[26].versos[25] = wxT("Judas, que o traiu, perguntou: Porventura sou eu, Mestre? Respondeu-lhe Jesus: Tu o disseste.");
    b->dados[MATEUS].capitulos[26].versos[26] = wxT("Enquanto comiam, Jesus tomou o pão e, abençoando-o, o partiu e o deu aos discípulos, dizendo: Tomai, comei; isto é o meu corpo.");
    b->dados[MATEUS].capitulos[26].versos[27] = wxT("Tomando o cálice, rendeu graças e deu-lho, dizendo: Bebei dele todos;");
    b->dados[MATEUS].capitulos[26].versos[28] = wxT("porque este é o meu sangue, o sangue da aliança, que é derramado por muitos para remissão de pecados.");
    b->dados[MATEUS].capitulos[26].versos[29] = wxT("Mas digo-vos que desta hora em diante não beberei deste fruto da videira, até aquele dia em que o hei de beber novo convosco no reino de meu Pai.");
    b->dados[MATEUS].capitulos[26].versos[30] = wxT("E tendo cantado um hino, saíram para o Monte das Oliveiras.");
    b->dados[MATEUS].capitulos[26].versos[31] = wxT("Então Jesus lhes disse: Todos vós esta noite vos escandalizareis de mim; pois está escrito: Ferirei o pastor, e as ovelhas do rebanho se dispersarão.");
    b->dados[MATEUS].capitulos[26].versos[32] = wxT("Todavia, depois que eu ressurgir, irei adiante de vós para a Galiléia.");
    b->dados[MATEUS].capitulos[26].versos[33] = wxT("Mas Pedro, respondendo, disse-lhe: Ainda que todos se escandalizem de ti, eu nunca me escandalizarei.");
    b->dados[MATEUS].capitulos[26].versos[34] = wxT("Disse-lhe Jesus: Em verdade te digo que esta noite, antes que o galo cante três vezes me negarás.");
    b->dados[MATEUS].capitulos[26].versos[35] = wxT("Respondeu-lhe Pedro: Ainda que me seja necessário morrer contigo, de modo algum te negarei. E o mesmo disseram todos os discípulos.");
    b->dados[MATEUS].capitulos[26].versos[36] = wxT("Então foi Jesus com eles a um lugar chamado Getsêmani, e disse aos discípulos: Sentai-vos aqui, enquanto eu vou ali orar.");
    b->dados[MATEUS].capitulos[26].versos[37] = wxT("E levando consigo Pedro e os dois filhos de Zebedeu, começou a entristecer-se e a angustiar-se.");
    b->dados[MATEUS].capitulos[26].versos[38] = wxT("Então lhes disse: A minha alma está triste até a morte; ficai aqui e vigiai comigo.");
    b->dados[MATEUS].capitulos[26].versos[39] = wxT("E adiantando-se um pouco, prostrou-se com o rosto em terra e orou, dizendo: Meu Pai, se é possível, passa de mim este cálice; todavia, não seja como eu quero, mas como tu queres.");
    b->dados[MATEUS].capitulos[26].versos[40] = wxT("Voltando para os discípulos, achou-os dormindo; e disse a Pedro: Assim nem uma hora pudestes vigiar comigo?");
    b->dados[MATEUS].capitulos[26].versos[41] = wxT("Vigiai e orai, para que não entreis em tentação; o espírito, na verdade, está pronto, mas a carne é fraca.");
    b->dados[MATEUS].capitulos[26].versos[42] = wxT("Retirando-se mais uma vez, orou, dizendo: Pai meu, se este cálice não pode passar sem que eu o beba, faça-se a tua vontade.");
    b->dados[MATEUS].capitulos[26].versos[43] = wxT("E, voltando outra vez, achou-os dormindo, porque seus olhos estavam carregados.");
    b->dados[MATEUS].capitulos[26].versos[44] = wxT("Deixando-os novamente, foi orar terceira vez, repetindo as mesmas palavras.");
    b->dados[MATEUS].capitulos[26].versos[45] = wxT("Então voltou para os discípulos e disse-lhes: Dormi agora e descansai. Eis que é chegada a hora, e o Filho do homem está sendo entregue nas mãos dos pecadores.");
    b->dados[MATEUS].capitulos[26].versos[46] = wxT("Levantai-vos, vamo-nos; eis que é chegado aquele que me trai.");
    b->dados[MATEUS].capitulos[26].versos[47] = wxT("E estando ele ainda a falar, eis que veio Judas, um dos doze, e com ele grande multidão com espadas e varapaus, vinda da parte dos principais sacerdotes e dos anciãos do povo.");
    b->dados[MATEUS].capitulos[26].versos[48] = wxT("Ora, o que o traía lhes havia dado um sinal, dizendo: Aquele que eu beijar, esse é: prendei-o.");
    b->dados[MATEUS].capitulos[26].versos[49] = wxT("E logo, aproximando-se de Jesus disse: Salve, Rabi. E o beijou.");
    b->dados[MATEUS].capitulos[26].versos[50] = wxT("Jesus, porém, lhe disse: Amigo, a que vieste? Nisto, aproximando-se eles, lançaram mão de Jesus, e o prenderam.");
    b->dados[MATEUS].capitulos[26].versos[51] = wxT("E eis que um dos que estavam com Jesus, estendendo a mão, puxou da espada e, ferindo o servo do sumo sacerdote, cortou-lhe uma orelha.");
    b->dados[MATEUS].capitulos[26].versos[52] = wxT("Então Jesus lhe disse: Mete a tua espada no seu lugar; porque todos os que lançarem mão da espada, à espada morrerão.");
    b->dados[MATEUS].capitulos[26].versos[53] = wxT("Ou pensas tu que eu não poderia rogar a meu Pai, e que ele não me mandaria agora mesmo mais de doze legiões de anjos?");
    b->dados[MATEUS].capitulos[26].versos[54] = wxT("Como, pois, se cumpririam as Escrituras, que dizem que assim convém que aconteça?");
    b->dados[MATEUS].capitulos[26].versos[55] = wxT("Disse Jesus à multidão naquela hora: Saístes com espadas e varapaus para me prender, como a um salteador? Todos os dias estava eu sentado no templo ensinando, e não me prendestes.");
    b->dados[MATEUS].capitulos[26].versos[56] = wxT("Mas tudo isso aconteceu para que se cumprissem as Escrituras dos profetas. Então todos os discípulos, deixando-o fugiram.");
    b->dados[MATEUS].capitulos[26].versos[57] = wxT("Aqueles que prenderam a Jesus levaram-no à presença do sumo sacerdote Caifás, onde os escribas e os anciãos estavam reunidos.");
    b->dados[MATEUS].capitulos[26].versos[58] = wxT("E Pedro o seguia de longe até o pátio do sumo sacerdote; e entrando, sentou-se entre os guardas, para ver o fim.");
    b->dados[MATEUS].capitulos[26].versos[59] = wxT("Ora, os principais sacerdotes e todo o sinédrio buscavam falso testemunho contra Jesus, para poderem entregá-lo à morte;");
    b->dados[MATEUS].capitulos[26].versos[60] = wxT("e não achavam, apesar de se apresentarem muitas testemunhas falsas. Mas por fim compareceram duas,");
    b->dados[MATEUS].capitulos[26].versos[61] = wxT("e disseram: Este disse: Posso destruir o santuário de Deus, e reedificá-lo em três dias.");
    b->dados[MATEUS].capitulos[26].versos[62] = wxT("Levantou-se então o sumo sacerdote e perguntou-lhe: Nada respondes? Que é que estes depõem contra ti?");
    b->dados[MATEUS].capitulos[26].versos[63] = wxT("Jesus, porém, guardava silêncio. E o sumo sacerdote disse-lhe: Conjuro-te pelo Deus vivo que nos digas se tu és o Cristo, o Filho do Deus.");
    b->dados[MATEUS].capitulos[26].versos[64] = wxT("Respondeu-lhe Jesus: É como disseste; contudo vos digo que vereis em breve o Filho do homem assentado à direita do Poder, e vindo sobre as nuvens do céu.");
    b->dados[MATEUS].capitulos[26].versos[65] = wxT("Então o sumo sacerdote rasgou as suas vestes, dizendo: Blasfemou; para que precisamos ainda de testemunhas? Eis que agora acabais de ouvir a sua blasfêmia.");
    b->dados[MATEUS].capitulos[26].versos[66] = wxT("Que vos parece? Responderam eles: É réu de morte.");
    b->dados[MATEUS].capitulos[26].versos[67] = wxT("Então uns lhe cuspiram no rosto e lhe deram socos;");
    b->dados[MATEUS].capitulos[26].versos[68] = wxT("e outros o esbofetearam, dizendo: Profetiza-nos, ó Cristo, quem foi que te bateu?");
    b->dados[MATEUS].capitulos[26].versos[69] = wxT("Ora, Pedro estava sentado fora, no pátio; e aproximou-se dele uma criada, que disse: Tu também estavas com Jesus, o galileu.");
    b->dados[MATEUS].capitulos[26].versos[70] = wxT("Mas ele negou diante de todos, dizendo: Não sei o que dizes.");
    b->dados[MATEUS].capitulos[26].versos[71] = wxT("E saindo ele para o vestíbulo, outra criada o viu, e disse aos que ali estavam: Este também estava com Jesus, o nazareno.");
    b->dados[MATEUS].capitulos[26].versos[72] = wxT("E ele negou outra vez, e com juramento: Não conheço tal homem.");
    b->dados[MATEUS].capitulos[26].versos[73] = wxT("E daí a pouco, aproximando-se os que ali estavam, disseram a Pedro: Certamente tu também és um deles pois a tua fala te denuncia.");
    b->dados[MATEUS].capitulos[26].versos[74] = wxT("Então começou ele a praguejar e a jurar, dizendo: Não conheço esse homem. E imediatamente o galo cantou.");
    b->dados[MATEUS].capitulos[26].versos[75] = wxT("E Pedro lembrou-se do que dissera Jesus: Antes que o galo cante, três vezes me negarás. E, saindo dali, chorou amargamente.");

    b->dados[MATEUS].capitulos[27].versos[1] = wxT("Ora, chegada a manhã, todos os principais sacerdotes e os anciãos do povo entraram em conselho contra Jesus, para o matarem;");
    b->dados[MATEUS].capitulos[27].versos[2] = wxT("e, maniatando-o, levaram-no e o entregaram a Pilatos, o governador.");
    b->dados[MATEUS].capitulos[27].versos[3] = wxT("Então Judas, aquele que o traíra, vendo que Jesus fora condenado, devolveu, compungido, as trinta moedas de prata aos anciãos, dizendo:");
    b->dados[MATEUS].capitulos[27].versos[4] = wxT("Pequei, traindo o sangue inocente. Responderam eles: Que nos importa? Seja isto lá contigo.");
    b->dados[MATEUS].capitulos[27].versos[5] = wxT("E tendo ele atirado para dentro do santuário as moedas de prata, retirou-se, e foi enforcar-se.");
    b->dados[MATEUS].capitulos[27].versos[6] = wxT("Os principais sacerdotes, pois, tomaram as moedas de prata, e disseram: Não é lícito metê-las no cofre das ofertas, porque é preço de sangue.");
    b->dados[MATEUS].capitulos[27].versos[7] = wxT("E, tendo deliberado em conselho, compraram com elas o campo do oleiro, para servir de cemitério para os estrangeiros.");
    b->dados[MATEUS].capitulos[27].versos[8] = wxT("Por isso tem sido chamado aquele campo, até o dia de hoje, Campo de Sangue.");
    b->dados[MATEUS].capitulos[27].versos[9] = wxT("Cumpriu-se, então, o que foi dito pelo profeta Jeremias: Tomaram as trinta moedas de prata, preço do que foi avaliado, a quem certos filhos de Israel avaliaram,");
    b->dados[MATEUS].capitulos[27].versos[10] = wxT("e deram-nas pelo campo do oleiro, assim como me ordenou o Senhor.");
    b->dados[MATEUS].capitulos[27].versos[11] = wxT("Jesus, pois, ficou em pé diante do governador; e este lhe perguntou: És tu o rei dos judeus? Respondeu-lhe Jesus: É como dizes.");
    b->dados[MATEUS].capitulos[27].versos[12] = wxT("Mas ao ser acusado pelos principais sacerdotes e pelos anciãos, nada respondeu.");
    b->dados[MATEUS].capitulos[27].versos[13] = wxT("Perguntou-lhe então Pilatos: Não ouves quantas coisas testificam contra ti?");
    b->dados[MATEUS].capitulos[27].versos[14] = wxT("E Jesus não lhe respondeu a uma pergunta sequer; de modo que o governador muito se admirava.");
    b->dados[MATEUS].capitulos[27].versos[15] = wxT("Ora, por ocasião da festa costumava o governador soltar um preso, escolhendo o povo aquele que quisesse.");
    b->dados[MATEUS].capitulos[27].versos[16] = wxT("Nesse tempo tinham um preso notório, chamado Barrabás.");
    b->dados[MATEUS].capitulos[27].versos[17] = wxT("Portanto, estando o povo reunido, perguntou-lhe Pilatos: Qual quereis que vos solte? Barrabás, ou Jesus, chamado o Cristo?");
    b->dados[MATEUS].capitulos[27].versos[18] = wxT("Pois sabia que por inveja o haviam entregado.");
    b->dados[MATEUS].capitulos[27].versos[19] = wxT("E estando ele assentado no tribunal, sua mulher mandou dizer-lhe: Não te envolvas na questão desse justo, porque muito sofri hoje em sonho por causa dele.");
    b->dados[MATEUS].capitulos[27].versos[20] = wxT("Mas os principais sacerdotes e os anciãos persuadiram as multidões a que pedissem Barrabás e fizessem morrer Jesus.");
    b->dados[MATEUS].capitulos[27].versos[21] = wxT("O governador, pois, perguntou-lhes: Qual dos dois quereis que eu vos solte? E disseram: Barrabás.");
    b->dados[MATEUS].capitulos[27].versos[22] = wxT("Tornou-lhes Pilatos: Que farei então de Jesus, que se chama Cristo? Disseram todos: Seja crucificado.");
    b->dados[MATEUS].capitulos[27].versos[23] = wxT("Pilatos, porém, disse: Pois que mal fez ele? Mas eles clamavam ainda mais: Seja crucificado.");
    b->dados[MATEUS].capitulos[27].versos[24] = wxT("Ao ver Pilatos que nada conseguia, mas pelo contrário que o tumulto aumentava, mandando trazer água, lavou as mãos diante da multidão, dizendo: Sou inocente do sangue deste homem; seja isso lá convosco.");
    b->dados[MATEUS].capitulos[27].versos[25] = wxT("E todo o povo respondeu: O seu sangue caia sobre nós e sobre nossos filhos.");
    b->dados[MATEUS].capitulos[27].versos[26] = wxT("Nisso os soldados do governador levaram Jesus ao pretório, e reuniram em torno dele toda a corte.");
    b->dados[MATEUS].capitulos[27].versos[27] = wxT("E, despindo-o, vestiram-lhe um manto escarlate;");
    b->dados[MATEUS].capitulos[27].versos[28] = wxT("e tecendo uma coroa de espinhos, puseram-lha na cabeça, e na mão direita uma cana, e ajoelhando-se diante dele, o escarneciam, dizendo: Salve, rei dos judeus!");
    b->dados[MATEUS].capitulos[27].versos[29] = wxT("E, cuspindo nele, tiraram-lhe a cana, e davam-lhe com ela na cabeça.");
    b->dados[MATEUS].capitulos[27].versos[30] = wxT("Depois de o terem escarnecido, despiram-lhe o manto, puseram-lhe as suas vestes, e levaram-no para ser crucificado.");
    b->dados[MATEUS].capitulos[27].versos[31] = wxT("Ao saírem, encontraram um homem cireneu, chamado Simão, a quem obrigaram a levar a cruz de Jesus.");
    b->dados[MATEUS].capitulos[27].versos[32] = wxT("Quando chegaram ao lugar chamado Gólgota, que quer dizer, lugar da Caveira,");
    b->dados[MATEUS].capitulos[27].versos[33] = wxT("deram-lhe a beber vinho misturado com fel; mas ele, provando-o, não quis beber.");
    b->dados[MATEUS].capitulos[27].versos[34] = wxT("Então, depois de o crucificarem, repartiram as vestes dele, lançando sortes, {para que se cumprisse o que foi dito pelo profeta: Repartiram entre si as minhas vestes, e sobre a minha túnica deitaram sortes.}");
    b->dados[MATEUS].capitulos[27].versos[35] = wxT("E, sentados, ali o guardavam.");
    b->dados[MATEUS].capitulos[27].versos[36] = wxT("Puseram-lhe por cima da cabeça a sua acusação escrita: ESTE É JESUS, O REI DOS JUDEUS.");
    b->dados[MATEUS].capitulos[27].versos[37] = wxT("Então foram crucificados com ele dois salteadores, um à direita, e outro à esquerda.");
    b->dados[MATEUS].capitulos[27].versos[38] = wxT("E os que iam passando blasfemavam dele, meneando a cabeça");
    b->dados[MATEUS].capitulos[27].versos[39] = wxT("e dizendo: Tu, que destróis o santuário e em três dias o reedificas, salva-te a ti mesmo; se és Filho de Deus, desce da cruz.");
    b->dados[MATEUS].capitulos[27].versos[40] = wxT("De igual modo também os principais sacerdotes, com os escribas e anciãos, escarnecendo, diziam:");
    b->dados[MATEUS].capitulos[27].versos[41] = wxT("A outros salvou; a si mesmo não pode salvar. Rei de Israel é ele; desça agora da cruz, e creremos nele;");
    b->dados[MATEUS].capitulos[27].versos[42] = wxT("confiou em Deus, livre-o ele agora, se lhe quer bem; porque disse: Sou Filho de Deus.");
    b->dados[MATEUS].capitulos[27].versos[43] = wxT("O mesmo lhe lançaram em rosto também os salteadores que com ele foram crucificados.");
    b->dados[MATEUS].capitulos[27].versos[44] = wxT("E, desde a hora sexta, houve trevas sobre toda a terra, até a hora nona.");
    b->dados[MATEUS].capitulos[27].versos[45] = wxT("Cerca da hora nona, bradou Jesus em alta voz, dizendo: Eli, Eli, lamá sabactani; isto é, Deus meu, Deus meu, por que me desamparaste?");
    b->dados[MATEUS].capitulos[27].versos[46] = wxT("Alguns dos que ali estavam, ouvindo isso, diziam: Ele chama por Elias.");
    b->dados[MATEUS].capitulos[27].versos[47] = wxT("E logo correu um deles, tomou uma esponja, ensopou-a em vinagre e, pondo-a numa cana, dava-lhe de beber.");
    b->dados[MATEUS].capitulos[27].versos[48] = wxT("Os outros, porém, disseram: Deixa, vejamos se Elias vem salvá-lo.");
    b->dados[MATEUS].capitulos[27].versos[49] = wxT("De novo bradou Jesus com grande voz, e entregou o espírito.");
    b->dados[MATEUS].capitulos[27].versos[50] = wxT("E eis que o véu do santuário se rasgou em dois, de alto a baixo; a terra tremeu, as pedras se fenderam,");
    b->dados[MATEUS].capitulos[27].versos[51] = wxT("os sepulcros se abriram, e muitos corpos de santos que tinham dormido foram ressuscitados;");
    b->dados[MATEUS].capitulos[27].versos[52] = wxT("e, saindo dos sepulcros, depois da ressurreição dele, entraram na cidade santa, e apareceram a muitos.");
    b->dados[MATEUS].capitulos[27].versos[53] = wxT("ora, o centurião e os que com ele guardavam Jesus, vendo o terremoto e as coisas que aconteciam, tiveram grande temor, e disseram: Verdadeiramente este era filho de Deus.");
    b->dados[MATEUS].capitulos[27].versos[54] = wxT("Também estavam ali, olhando de longe, muitas mulheres que tinham seguido Jesus desde a Galiléia para o ouvir;");
    b->dados[MATEUS].capitulos[27].versos[55] = wxT("entre as quais se achavam Maria Madalena, Maria, mãe de Tiago e de José, e a mãe dos filhos de Zebedeu.");
    b->dados[MATEUS].capitulos[27].versos[56] = wxT("Ao cair da tarde, veio um homem rico de Arimatéia, chamado José, que também era discípulo de Jesus.");
    b->dados[MATEUS].capitulos[27].versos[57] = wxT("Esse foi a Pilatos e pediu o corpo de Jesus. Então Pilatos mandou que lhe fosse entregue.");
    b->dados[MATEUS].capitulos[27].versos[58] = wxT("E José, tomando o corpo, envolveu-o num pano limpo, de linho,");
    b->dados[MATEUS].capitulos[27].versos[59] = wxT("e depositou-o no seu sepulcro novo, que havia aberto em rocha; e, rodando uma grande pedra para a porta do sepulcro, retirou-se.");
    b->dados[MATEUS].capitulos[27].versos[60] = wxT("Mas achavam-se ali Maria Madalena e a outra Maria, sentadas defronte do sepulcro.");
    b->dados[MATEUS].capitulos[27].versos[61] = wxT("No dia seguinte, isto é, o dia depois da preparação, reuniram-se os principais sacerdotes e os fariseus perante Pilatos,");
    b->dados[MATEUS].capitulos[27].versos[62] = wxT("e disseram: Senhor, lembramo-nos de que aquele embusteiro, quando ainda vivo, afirmou: Depois de três dias ressurgirei.");
    b->dados[MATEUS].capitulos[27].versos[63] = wxT("Manda, pois, que o sepulcro seja guardado com segurança até o terceiro dia; para não suceder que, vindo os discípulos, o furtem e digam ao povo: Ressurgiu dos mortos; e assim o último embuste será pior do que o primeiro.");
    b->dados[MATEUS].capitulos[27].versos[64] = wxT("Disse-lhes Pilatos: Tendes uma guarda; ide, tornai-o seguro, como entendeis.");
    b->dados[MATEUS].capitulos[27].versos[65] = wxT("Foram, pois, e tornaram seguro o sepulcro, selando a pedra, e deixando ali a guarda.");

    b->dados[MATEUS].capitulos[28].versos[1] = wxT("No fim do sábado, quando já despontava o primeiro dia da semana, Maria Madalena e a outra Maria foram ver o sepulcro.");
    b->dados[MATEUS].capitulos[28].versos[2] = wxT("E eis que houvera um grande terremoto; pois um anjo do Senhor descera do céu e, chegando-se, removera a pedra e estava sentado sobre ela.");
    b->dados[MATEUS].capitulos[28].versos[3] = wxT("o seu aspecto era como um relâmpago, e as suas vestes brancas como a neve.");
    b->dados[MATEUS].capitulos[28].versos[4] = wxT("E de medo dele tremeram os guardas, e ficaram como mortos.");
    b->dados[MATEUS].capitulos[28].versos[5] = wxT("Mas o anjo disse às mulheres: Não temais vós; pois eu sei que buscais a Jesus, que foi crucificado.");
    b->dados[MATEUS].capitulos[28].versos[6] = wxT("Não está aqui, porque ressurgiu, como ele disse. Vinde, vede o lugar onde jazia;");
    b->dados[MATEUS].capitulos[28].versos[7] = wxT("e ide depressa, e dizei aos seus discípulos que ressurgiu dos mortos; e eis que vai adiante de vós para a Galiléia; ali o vereis. Eis que vo-lo tenho dito.");
    b->dados[MATEUS].capitulos[28].versos[8] = wxT("E, partindo elas pressurosamente do sepulcro, com temor e grande alegria, correram a anunciá-lo aos discípulos.");
    b->dados[MATEUS].capitulos[28].versos[9] = wxT("E eis que Jesus lhes veio ao encontro, dizendo: Salve. E elas, aproximando-se, abraçaram-lhe os pés, e o adoraram.");
    b->dados[MATEUS].capitulos[28].versos[10] = wxT("Então lhes disse Jesus: Não temais; ide dizer a meus irmãos que vão para a Galiléia; ali me verão.");
    b->dados[MATEUS].capitulos[28].versos[11] = wxT("Ora, enquanto elas iam, eis que alguns da guarda foram à cidade, e contaram aos principais sacerdotes tudo quanto havia acontecido.");
    b->dados[MATEUS].capitulos[28].versos[12] = wxT("E congregados eles com os anciãos e tendo consultado entre si, deram muito dinheiro aos soldados,");
    b->dados[MATEUS].capitulos[28].versos[13] = wxT("e ordenaram-lhes que dissessem: Vieram de noite os seus discípulos e, estando nós dormindo, furtaram-no.");
    b->dados[MATEUS].capitulos[28].versos[14] = wxT("E, se isto chegar aos ouvidos do governador, nós o persuadiremos, e vos livraremos de cuidado.");
    b->dados[MATEUS].capitulos[28].versos[15] = wxT("Então eles, tendo recebido o dinheiro, fizeram como foram instruídos. E essa história tem-se divulgado entre os judeus até o dia de hoje.");
    b->dados[MATEUS].capitulos[28].versos[16] = wxT("Partiram, pois, os onze discípulos para a Galiléia, para o monte onde Jesus lhes designara.");
    b->dados[MATEUS].capitulos[28].versos[17] = wxT("Quando o viram, o adoraram; mas alguns duvidaram.");
    b->dados[MATEUS].capitulos[28].versos[18] = wxT("E, aproximando-se Jesus, falou-lhes, dizendo: Foi-me dada toda a autoridade no céu e na terra.");
    b->dados[MATEUS].capitulos[28].versos[19] = wxT("Portanto ide, fazei discípulos de todas as nações, batizando-os em nome do Pai, e do Filho, e do Espírito Santo;");
    b->dados[MATEUS].capitulos[28].versos[20] = wxT("ensinando-os a observar todas as coisas que eu vos tenho mandado; e eis que eu estou convosco todos os dias, até a consumação dos séculos.");

}
